// Every onSnapshot below is wired with this, so if a listener ever gets
// blocked (e.g. by a rules change), the console tells us exactly which
// one - rather than every listener producing the same generic, impossible
// to distinguish "permission-denied" message.
function logSnapErr(label) {
  return (err) => console.error(`[snapshot:${label}]`, err?.code || err);
}

// Lightweight, dependency-free sound effects using the Web Audio API - no
// external audio files to host, license, or fetch. Every entry point below
// is wrapped in try/catch so a sound failure (e.g. an older browser, or a
// browser blocking audio before any user gesture) can never interrupt the
// actual save/sale it's celebrating.
//
// Browsers only allow creating/resuming an AudioContext synchronously
// within a genuine user gesture (click/tap/keypress). Our sounds fire
// *after* an `await` (once the Firestore save actually finishes), which by
// then no longer counts as "inside" that gesture - so a context created at
// that point would stay silently suspended. Fix: "unlock" one shared
// context as early as possible, on the very first interaction anywhere in
// the app (signing in counts), so it's already running by the time any
// save/sale actually completes and wants to play a sound.
let sharedAudioCtx = null;
function unlockAudioCtx() {
  try {
    const Ctx = window.AudioContext || window.webkitAudioContext;
    if (!Ctx) return;
    if (!sharedAudioCtx) sharedAudioCtx = new Ctx();
    if (sharedAudioCtx.state === 'suspended') sharedAudioCtx.resume();
  } catch (e) { /* ignore - sound just won't play */ }
}
if (typeof document !== 'undefined') {
  ['pointerdown', 'keydown', 'touchstart'].forEach((evt) =>
    document.addEventListener(evt, unlockAudioCtx, { once: true, passive: true })
  );
}

function getAudioCtx() {
  try {
    if (!sharedAudioCtx) {
      const Ctx = window.AudioContext || window.webkitAudioContext;
      if (!Ctx) return null;
      sharedAudioCtx = new Ctx();
    }
    if (sharedAudioCtx.state === 'suspended') sharedAudioCtx.resume();
    return sharedAudioCtx;
  } catch (e) {
    return null;
  }
}

function playTone(ctx, { freq, start, duration, type = 'sine', peakGain = 0.18 }) {
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = type;
  osc.frequency.setValueAtTime(freq, ctx.currentTime + start);
  gain.gain.setValueAtTime(0, ctx.currentTime + start);
  gain.gain.linearRampToValueAtTime(peakGain, ctx.currentTime + start + 0.01);
  gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + start + duration);
  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start(ctx.currentTime + start);
  osc.stop(ctx.currentTime + start + duration + 0.02);
}

// A short, pleasant two-note "added" chime - played whenever something new
// is created: item, supplier, category, location, order, or staff account.
function playAddSound() {
  try {
    const ctx = getAudioCtx();
    if (!ctx) return;
    playTone(ctx, { freq: 587.33, start: 0, duration: 0.11, type: 'sine', peakGain: 0.16 }); // D5
    playTone(ctx, { freq: 880.00, start: 0.09, duration: 0.16, type: 'sine', peakGain: 0.18 }); // A5
  } catch (e) { /* decorative - never break the app over a sound */ }
}

// A bright "cha-ching" cash-register flourish, reserved for completed sales
// only - kept distinct from playAddSound() so it stays a meaningful signal
// rather than blending into general background noise.
function playSaleSound() {
  try {
    const ctx = getAudioCtx();
    if (!ctx) return;
    // "Cha" - a quick bright double-hit
    playTone(ctx, { freq: 1046.50, start: 0, duration: 0.09, type: 'square', peakGain: 0.12 }); // C6
    playTone(ctx, { freq: 1318.51, start: 0.06, duration: 0.09, type: 'square', peakGain: 0.12 }); // E6
    // "Ching" - a longer bell-like ring with a couple of shimmering harmonics
    playTone(ctx, { freq: 1760.00, start: 0.15, duration: 0.55, type: 'sine', peakGain: 0.20 }); // A6
    playTone(ctx, { freq: 2637.02, start: 0.16, duration: 0.45, type: 'sine', peakGain: 0.10 }); // E7
    playTone(ctx, { freq: 3520.00, start: 0.17, duration: 0.35, type: 'sine', peakGain: 0.06 }); // A7 shimmer
  } catch (e) { /* decorative - never break the app over a sound */ }
}

// Items store suppliers as `supplierIds` (array - multi-supplier support).
// Older items from before this change may still only have the single
// `supplierId` field; this normalizes either shape into an array so every
// view can treat all items identically without caring which one they have.
function getSupplierIds(item) {
  if (Array.isArray(item?.supplierIds)) return item.supplierIds;
  return item?.supplierId ? [item.supplierId] : [];
}

// Items store the acquisition cost as `unitCost` ("Base Cost" in the UI -
// this already meant "cost basis" even before markup/pricing existed, so
// no field rename/migration needed). Selling price is derived from that
// base cost plus a markup, either a percentage on top of cost or a flat
// peso amount added to it, then persisted on the item as `sellingPrice` so
// POS and profit calculations don't need to recompute it every time.
function computeSellingPrice(baseCost, markupType, markupValue) {
  const cost = Math.max(0, Number(baseCost) || 0);
  const markup = Math.max(0, Number(markupValue) || 0);
  const price = markupType === 'fixed' ? cost + markup : cost * (1 + markup / 100);
  return Math.round(price * 100) / 100;
}

