function BackgroundDecor({ variant = 'app' }) {
  const set = DECOR_SETS[variant] || DECOR_SETS.app;
  return (
    <div style={styles.decorLayer} aria-hidden="true">
      {set.map(({ Icon, top, left, size, rotate, color, opacity }, i) => (
        <Icon
          key={i}
          size={size}
          color={color}
          strokeWidth={1.4}
          style={{
            position: 'absolute', top, left, opacity: opacity ?? 0.24,
            transform: `rotate(${rotate}deg)`,
          }}
        />
      ))}
    </div>
  );
}

// ---------------------------------------------------------------------------
// RBAC: centralized roles + permissions. Add a new role here and it's
// automatically available everywhere permission checks happen.
// ---------------------------------------------------------------------------
const ROLES = {
  superadmin: 'Super Admin',
  client: 'Client',
  staff: 'Staff',
};

const PERMISSIONS = {
  superadmin: {
    viewInventory: true, editInventory: true, deleteInventory: true,
    manageCategories: true, manageSuppliers: true, manageLocations: true, manageOrders: true,
    stockReceive: true, stockIssue: true, editMarkup: true,
    pos: true, viewReports: true, viewSalesReports: false, print: true, cancelSales: true,
    manageUsers: true, manageAllRoles: true, manageSystem: true,
    viewOwnSales: false, viewActivityLogs: true, manageUserProfiles: true, createStaff: true,
  },
  client: {
    viewInventory: true, editInventory: true, deleteInventory: true,
    manageCategories: true, manageSuppliers: true, manageLocations: true, manageOrders: true,
    stockReceive: true, stockIssue: true, editMarkup: true,
    pos: true, viewReports: true, viewSalesReports: true, print: true, cancelSales: true,
    manageUsers: false, manageAllRoles: false, manageSystem: false,
    viewOwnSales: false, viewActivityLogs: true, manageUserProfiles: true, createStaff: true,
  },
  staff: {
    viewInventory: true, editInventory: false, deleteInventory: false,
    manageCategories: false, manageSuppliers: false, manageLocations: false, manageOrders: false,
    stockReceive: true, stockIssue: false, editMarkup: true,
    pos: true, viewReports: false, viewSalesReports: false, print: false, cancelSales: false,
    manageUsers: false, manageAllRoles: false, manageSystem: false,
    viewOwnSales: true, viewActivityLogs: false, manageUserProfiles: false, createStaff: false,
  },
};

function can(role, permission) {
  return !!PERMISSIONS[role]?.[permission];
}

// Which permission (if any) gates each sidebar view. `null` = any approved user.
const VIEW_PERMISSIONS = {
  overview: null,
  pos: 'pos',
  inventory: 'viewInventory',
  staffInventory: 'editInventory',
  suppliers: 'manageSuppliers',
  categories: 'manageCategories',
  locations: 'manageLocations',
  orders: 'manageOrders',
  delivery: 'viewReports',
  sales: 'viewSalesReports',
  mysales: 'viewOwnSales',
  history: 'viewReports',
  approvals: 'manageUserProfiles',
  activity: 'viewActivityLogs',
  myprofile: 'manageUserProfiles',
};

function canAccessView(role, viewKey) {
  const perm = VIEW_PERMISSIONS[viewKey];
  return perm === null || perm === undefined || can(role, perm);
}

// Backward-compatible role resolver: older accounts only have `isAdmin`, not
// `role`. Treat isAdmin:true as superadmin, everyone else defaults to staff
// (the lowest-privilege role) until a manager assigns something higher.
function resolveRole(profile) {
  if (!profile) return 'staff';
  if (profile.role && PERMISSIONS[profile.role]) return profile.role;
  if (profile.isAdmin) return 'superadmin';
  return 'staff';
}

// A short, human-readable ID distinct from the long Firebase account ID.
// Timestamp + random suffix keeps collisions practically impossible without
// needing a server-side counter.
function generateUserIdNumber() {
  return 'U-' + Date.now().toString(36).toUpperCase() + '-' + Math.random().toString(36).slice(2, 5).toUpperCase();
}

// Profile photos live inside the Firestore user doc (this app has no
// separate file storage), so they need to be small. Downscale to a square
// thumbnail and re-encode as compressed JPEG before it ever touches the
// database - a raw phone photo could otherwise be several MB.
function resizePhotoToDataUri(file, maxSize = 160, quality = 0.75) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error('Could not read the file'));
    reader.onload = () => {
      const img = new Image();
      img.onerror = () => reject(new Error('Could not read that image'));
      img.onload = () => {
        const side = Math.min(img.width, img.height);
        const sx = (img.width - side) / 2;
        const sy = (img.height - side) / 2;
        const canvas = document.createElement('canvas');
        canvas.width = maxSize;
        canvas.height = maxSize;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, sx, sy, side, side, 0, 0, maxSize, maxSize);
        resolve(canvas.toDataURL('image/jpeg', quality));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

