export default function InventorySystem() {
  const [user, setUser] = useState(null);
  const [authChecked, setAuthChecked] = useState(false);
  const [myProfile, setMyProfile] = useState(null);
  const [profileChecked, setProfileChecked] = useState(false);
  const [pendingUsers, setPendingUsers] = useState([]);
  const [approvedUsers, setApprovedUsers] = useState([]);
  const [branding, setBranding] = useState(null);
  const [tenantBranding, setTenantBranding] = useState(null);
  const [items, setItems] = useState([]);
  const [movements, setMovements] = useState([]);
  const [suppliers, setSuppliers] = useState([]);
  const [categories, setCategories] = useState([]);
  const [locations, setLocations] = useState([]);
  const [deliveryStatuses, setDeliveryStatuses] = useState({});
  const [sales, setSales] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loginLogs, setLoginLogs] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [view, setView] = useState('overview');
  const [search, setSearch] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [sortKey, setSortKey] = useState('name');
  const [itemModal, setItemModal] = useState(null);
  const [moveModal, setMoveModal] = useState(null);
  const [supplierModal, setSupplierModal] = useState(null);
  const [orderModal, setOrderModal] = useState(null);
  const [assignModal, setAssignModal] = useState(null);
  const [markupModal, setMarkupModal] = useState(null);
  const [selectedStaffUid, setSelectedStaffUid] = useState('');
  const [confirmModal, setConfirmModal] = useState(null); // {kind: 'item'|'supplier'|'order', target}
  const [deliveryStatusModal, setDeliveryStatusModal] = useState(null);
  const [toast, setToast] = useState(null);

  // history filters
  const [histSearch, setHistSearch] = useState('');
  const [histType, setHistType] = useState('All');
  const [histItem, setHistItem] = useState('All');

  // Auth: track sign-in state
  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      setUser(u);
      setAuthChecked(true);
    });
    return unsub;
  }, []);

  // Approval: ensure a users/{uid} profile exists, then subscribe to it live
  useEffect(() => {
    if (!user) { setMyProfile(null); setProfileChecked(false); return; }
    let unsub;
    setProfileChecked(false);
    (async () => {
      try {
        const ref = doc(db, 'users', user.uid);
        const snap = await getDoc(ref);
        if (!snap.exists()) {
          await setDoc(ref, {
            email: user.email || '', approved: false, isAdmin: false, role: 'staff', createdAt: Date.now(),
          }, { merge: true });
        }
      } catch (e) {
        console.error('Profile bootstrap error:', e);
      }
      unsub = onSnapshot(doc(db, 'users', user.uid), (d) => {
        setMyProfile(d.exists() ? d.data() : null);
        setProfileChecked(true);
      }, logSnapErr('myProfile'));
    })();
    return () => { if (unsub) unsub(); };
  }, [user]);

  const myRole = resolveRole(myProfile);
  const isManager = myRole === 'superadmin' || myRole === 'client';

  // Multi-tenancy: every piece of business data (items, suppliers, sales,
  // categories, etc.) is stamped with the `ownerId` of the tenant it belongs
  // to. A Client Admin IS a tenant, so their ownerId is their own uid. Staff
  // don't own a tenant - they inherit the ownerId of whichever Client Admin
  // created them (stored on their profile as `parentId`). Super Admin gets
  // their own tenant too, so their own inventory/sales stay separate from
  // every client's data, but they retain unscoped visibility into the
  // `users` collection so they can approve/manage accounts platform-wide.
  const ownerId = !user ? null
    : myRole === 'staff' ? (myProfile?.parentId || null)
    : user.uid;

  // Activity log: record a "login" entry each time a session starts. This is
  // a client-side approximation - it can't distinguish "just signed in" from
  // "reopened the app with a still-valid session," since both look the same
  // to the client SDK. Logout is recorded explicitly via handleSignOut below.
  useEffect(() => {
    // Wait for the tenant (ownerId) to resolve from the profile before
    // logging, so the entry is correctly scoped to the right Client Admin.
    if (!user || !ownerId) return;
    (async () => {
      try {
        const logId = 'l' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'loginLogs', logId), {
          uid: user.uid, email: user.email || '', type: 'login', timestamp: Date.now(), ownerId,
        });
      } catch (e) {
        console.error('Login log error:', e);
      }
    })();
  }, [user?.uid, ownerId]);

  const handleSignOut = async () => {
    if (user) {
      try {
        const logId = 'l' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'loginLogs', logId), {
          uid: user.uid, email: user.email || '', type: 'logout', timestamp: Date.now(), ownerId,
        });
      } catch (e) {
        console.error('Logout log error:', e);
      }
    }
    await signOut(auth);
  };

  // Branding (custom logo + theme): public read, so this works even on the
  // signed-out login screen. This is the PLATFORM default - Super Admin
  // only - applied at sign-in and to any tenant that hasn't set their own.
  useEffect(() => {
    const unsub = onSnapshot(doc(db, 'config', 'branding'), (d) => {
      setBranding(d.exists() ? d.data() : {});
    }, (err) => { logSnapErr('platformBranding')(err); setBranding({}); });
    return unsub;
  }, []);

  // Per-tenant branding override: each Client Admin can customize their own
  // logo/theme independently, without affecting the platform default or any
  // other tenant. Only meaningful once ownerId is known (i.e. after login),
  // since it lives at config/branding_{ownerId}.
  useEffect(() => {
    if (!ownerId) { setTenantBranding(null); return; }
    const unsub = onSnapshot(doc(db, 'config', 'branding_' + ownerId), (d) => {
      setTenantBranding(d.exists() ? d.data() : {});
    }, (err) => { logSnapErr('tenantBranding')(err); setTenantBranding({}); });
    return unsub;
  }, [ownerId]);

  // Effective branding: a tenant's own override wins field-by-field, falling
  // back to the platform default for anything the tenant hasn't customized.
  const effectiveBranding = {
    logoDataUri: tenantBranding?.logoDataUri ?? branding?.logoDataUri,
    themeKey: tenantBranding?.themeKey ?? branding?.themeKey,
  };
  const effectiveLogo = effectiveBranding.logoDataUri || LOGO_DATA_URI;
  const activeTheme = THEMES[effectiveBranding.themeKey] || THEMES[DEFAULT_THEME_KEY];

  // Super Admin manages Team Access for the whole platform (every account) -
  // an unfiltered collection listener, which works fine for them since
  // isSuperAdmin() alone (not combined with per-document field matching)
  // is trivially provable across the whole collection.
  //
  // A Client reads each of THEIR staff individually, driven by the
  // `staffUids` array recorded on their own profile (see
  // createStaffAccount). This sidesteps a Firestore list-query edge case:
  // a collection query filtered by `where('parentId', '==', myUid)` -
  // logically sound and confirmed correct against the security rules -
  // was nonetheless silently denied by Firestore with no reliable fix
  // found. Reading each staff document individually (a plain get(), not a
  // list) avoids that edge case entirely.
  const staffUidsKey = JSON.stringify(myProfile?.staffUids || []);
  useEffect(() => {
    if (!user || !isManager) { setPendingUsers([]); setApprovedUsers([]); return; }

    if (myRole === 'superadmin') {
      const unsub = onSnapshot(collection(db, 'users'), (snap) => {
        const all = snap.docs.map((d) => ({ id: d.id, ...d.data(), role: resolveRole(d.data()) }));
        setPendingUsers(all.filter((u) => !u.approved));
        setApprovedUsers(all.filter((u) => u.approved));
      }, logSnapErr('teamRoster'));
      return unsub;
    }

    const staffUids = JSON.parse(staffUidsKey);
    if (staffUids.length === 0) { setPendingUsers([]); setApprovedUsers([]); return; }

    const docsMap = {};
    const refresh = () => {
      const all = Object.values(docsMap);
      setPendingUsers(all.filter((u) => !u.approved));
      setApprovedUsers(all.filter((u) => u.approved));
    };
    const unsubs = staffUids.map((uid) =>
      onSnapshot(doc(db, 'users', uid), (d) => {
        if (d.exists()) docsMap[uid] = { id: d.id, ...d.data(), role: resolveRole(d.data()) };
        else delete docsMap[uid];
        refresh();
      }, logSnapErr('teamRoster'))
    );
    return () => unsubs.forEach((u) => u());
  }, [user, isManager, myRole, staffUidsKey]);

  // Lets a Client Admin (or Super Admin, for support) provision a Staff
  // account directly - no self-signup/approval step. Uses a throwaway
  // secondary Firebase App instance so creating the new auth user doesn't
  // sign the admin themselves out of their own session (the Firebase client
  // SDK otherwise switches the active session to whichever user was most
  // recently created).
  const createStaffAccount = async ({ email, password, fullName, username, contactNumber, address }) => {
    if (!can(myRole, 'createStaff') || !ownerId) {
      showToast("You don't have permission to add staff");
      return { ok: false };
    }
    let secondaryApp;
    try {
      secondaryApp = initializeApp(auth.app.options, 'staff-creation-' + Date.now());
      const secondaryAuth = getAuth(secondaryApp);
      // Critical: without this, the secondary app shares the SAME
      // persisted auth storage as our own (primary) session by default -
      // signing in/out a brand-new user on it can silently corrupt the
      // admin's own active session, causing their live listeners to start
      // throwing permission-denied shortly after. In-memory persistence
      // keeps it fully isolated.
      await setPersistence(secondaryAuth, inMemoryPersistence);
      const cred = await createUserWithEmailAndPassword(secondaryAuth, email.trim(), password);
      await setDoc(doc(db, 'users', cred.user.uid), {
        email: email.trim(), approved: true, isAdmin: false, role: 'staff',
        parentId: ownerId, createdAt: Date.now(), createdBy: user.uid,
        fullName: (fullName || '').trim(), username: (username || '').trim(),
        contactNumber: (contactNumber || '').trim(), address: (address || '').trim(),
        userIdNumber: generateUserIdNumber(),
      });
      // Record this staff member on OUR OWN profile too. This is what lets
      // Team Access find "my staff" via a simple read of our own document
      // instead of a collection-wide query for "anyone whose parentId is
      // me" - the former is a plain, reliable single-document read; the
      // latter turned out to be an unreliable Firestore list-query edge
      // case that silently denied results with no clear fix.
      await setDoc(doc(db, 'users', user.uid), {
        staffUids: arrayUnion(cred.user.uid),
      }, { merge: true });
      await signOut(secondaryAuth);
      playAddSound();
      logActivity('staff_created', { targetEmail: email.trim(), targetUid: cred.user.uid });
      showToast(`Staff account created for ${email.trim()}`);
      return { ok: true };
    } catch (e) {
      const msg = e?.code === 'auth/email-already-in-use'
        ? 'That email already has an account'
        : e?.code === 'auth/weak-password'
        ? 'Password should be at least 6 characters'
        : 'Could not create staff account — check your connection';
      showToast(msg);
      return { ok: false, error: e };
    } finally {
      if (secondaryApp) { try { await deleteApp(secondaryApp); } catch {} }
    }
  };

  const approveUser = async (uid) => {
    try {
      await setDoc(doc(db, 'users', uid), { approved: true }, { merge: true });
      showToast('Account approved');
    } catch (e) {
      showToast('Could not approve — check your connection');
    }
  };

  const denyUser = async (uid) => {
    try {
      await deleteDoc(doc(db, 'users', uid));
      showToast('Request removed');
    } catch (e) {
      showToast('Could not remove request — check your connection');
    }
  };

  const revokeUser = async (uid) => {
    try {
      await deleteDoc(doc(db, 'users', uid));
      showToast('Access revoked');
    } catch (e) {
      showToast('Could not revoke access — check your connection');
    }
  };

  const changeUserRole = async (uid, newRole) => {
    if (myRole !== 'superadmin') return;
    try {
      await setDoc(doc(db, 'users', uid), { role: newRole }, { merge: true });
      showToast(`Role updated to ${ROLES[newRole] || newRole}`);
    } catch (e) {
      showToast('Could not update role — check your connection');
    }
  };

  // Edits profile info (name/username/contact/address) - never role or
  // approval status, which stay behind the separate Team Access controls.
  // Anyone can edit their own; a manager can edit others' (Client limited to
  // Staff by the UI list they're given and by the Firestore rules).
  const updateUserProfile = async (uid, fields) => {
    const isSelf = uid === user.uid;
    if (!isSelf && !can(myRole, 'manageUserProfiles')) {
      showToast("You don't have permission to edit this profile");
      return;
    }
    try {
      const payload = {
        fullName: fields.fullName?.trim() || '',
        username: fields.username?.trim() || '',
        contactNumber: fields.contactNumber?.trim() || '',
        address: fields.address?.trim() || '',
      };
      // Only include photoDataUri when a new photo was actually picked, so
      // saving other fields never accidentally clears an existing photo.
      if (fields.photoDataUri !== undefined) payload.photoDataUri = fields.photoDataUri;
      await setDoc(doc(db, 'users', uid), payload, { merge: true });
      showToast('Profile updated');
    } catch (e) {
      showToast('Could not update profile — check your connection');
    }
  };

  // Firebase requires a recent sign-in before allowing a password change, so
  // we re-authenticate with the user's current password first - this also
  // doubles as confirming they actually know the current password before
  // letting them set a new one.
  const changePassword = async (currentPassword, newPassword) => {
    try {
      const credential = EmailAuthProvider.credential(user.email, currentPassword);
      await reauthenticateWithCredential(auth.currentUser, credential);
      await updatePassword(auth.currentUser, newPassword);
      showToast('Password updated');
      return { ok: true };
    } catch (e) {
      const msg = e?.code === 'auth/wrong-password' || e?.code === 'auth/invalid-credential'
        ? 'Current password is incorrect'
        : e?.code === 'auth/weak-password'
        ? 'New password should be at least 6 characters'
        : e?.code === 'auth/too-many-requests'
        ? 'Too many attempts — please wait a bit and try again'
        : 'Could not update password — check your connection';
      showToast(msg);
      return { ok: false, error: e };
    }
  };

  // Super Admin edits the platform default (shown at sign-in and to any
  // tenant without their own override). A Client Admin edits ONLY their own
  // tenant's branding doc - it can never affect the platform default or any
  // other Client Admin's portal.
  const brandingDocFor = (role) => (role === 'superadmin' ? 'branding' : 'branding_' + ownerId);

  const saveLogo = async (dataUri) => {
    if (!isManager) return;
    try {
      await setDoc(doc(db, 'config', brandingDocFor(myRole)), {
        logoDataUri: dataUri, ...(myRole === 'superadmin' ? {} : { ownerId }),
      }, { merge: true });
      showToast(myRole === 'superadmin' ? 'Logo updated for everyone' : 'Logo updated for your inventory portal');
    } catch (e) {
      showToast('Could not save logo — check your connection');
    }
  };

  const resetLogo = async () => {
    if (!isManager) return;
    try {
      await setDoc(doc(db, 'config', brandingDocFor(myRole)), {
        logoDataUri: null, ...(myRole === 'superadmin' ? {} : { ownerId }),
      }, { merge: true });
      showToast('Reverted to the default logo');
    } catch (e) {
      showToast('Could not reset logo — check your connection');
    }
  };

  const setThemeKey = async (key) => {
    if (!isManager) return;
    try {
      await setDoc(doc(db, 'config', brandingDocFor(myRole)), {
        themeKey: key, ...(myRole === 'superadmin' ? {} : { ownerId }),
      }, { merge: true });
      showToast(`Theme changed to ${THEMES[key]?.label || key}`);
    } catch (e) {
      showToast('Could not change theme — check your connection');
    }
  };


  // Data: seed once per tenant if empty, then subscribe to live Firestore
  // updates - every query below is filtered by `ownerId` so one Client
  // Admin's inventory, suppliers, movements, sales, and reports are never
  // visible to another tenant. Staff inherit their tenant's ownerId, so the
  // same filtered queries automatically give them exactly (and only) their
  // Client Admin's data - nothing more.
  useEffect(() => {
    if (!user || !myProfile?.approved || !ownerId) { setLoaded(false); return; }
    let unsubs = [];
    let cancelled = false;
    const categoriesDocId = 'categories_' + ownerId;
    const locationsDocId = 'locations_' + ownerId;

    (async () => {
      try {
        // Only the tenant owner (Client Admin / Super Admin) seeds their own
        // workspace - staff never trigger seeding, they just read it.
        if (isManager) {
          const itemsSnap = await getDocs(query(collection(db, 'items'), where('ownerId', '==', ownerId)));
          if (itemsSnap.empty) {
            const seed = seedItems().map((it) => ({ ...it, id: 'i' + Math.random().toString(36).slice(2, 9) }));
            await Promise.all(seed.map((it) => setDoc(doc(db, 'items', it.id), { ...it, ownerId, holderId: ownerId })));
            const moves = seedMovements(seed).map((m) => ({ ...m, id: 'm' + Math.random().toString(36).slice(2, 9) }));
            await Promise.all(moves.map((m) => setDoc(doc(db, 'movements', m.id), { ...m, ownerId })));
          }
          const suppliersSnap = await getDocs(query(collection(db, 'suppliers'), where('ownerId', '==', ownerId)));
          if (suppliersSnap.empty) {
            const seedSup = seedSuppliers().map((s) => ({ ...s, id: 's' + Math.random().toString(36).slice(2, 9) }));
            await Promise.all(seedSup.map((s) => setDoc(doc(db, 'suppliers', s.id), { ...s, ownerId })));
          }
          const catDoc = await getDoc(doc(db, 'config', categoriesDocId));
          if (!catDoc.exists()) {
            await setDoc(doc(db, 'config', categoriesDocId), { list: DEFAULT_CATEGORIES, ownerId });
          }
          const locDoc = await getDoc(doc(db, 'config', locationsDocId));
          if (!locDoc.exists()) {
            await setDoc(doc(db, 'config', locationsDocId), { list: DEFAULT_LOCATIONS, ownerId });
          }
        }
      } catch (e) {
        console.error('Seeding error:', e);
      }

      if (cancelled) return;

      // Staff only ever see stock assigned to THEM (holderId) - never the
      // Client Admin's master inventory or another staff member's stock.
      // Managers see the whole tenant's items regardless of holder, since
      // they need full oversight to assign/edit/reclaim stock.
      const itemsQuery = isManager
        ? query(collection(db, 'items'), where('ownerId', '==', ownerId))
        : query(collection(db, 'items'), where('ownerId', '==', ownerId), where('holderId', '==', user.uid));
      unsubs.push(onSnapshot(itemsQuery, (snap) => {
        setItems(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
      }, logSnapErr('items')));
      unsubs.push(onSnapshot(query(collection(db, 'suppliers'), where('ownerId', '==', ownerId)), (snap) => {
        setSuppliers(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
      }, logSnapErr('suppliers')));
      unsubs.push(onSnapshot(doc(db, 'config', categoriesDocId), (d) => {
        setCategories(d.exists() ? (d.data().list || []) : DEFAULT_CATEGORIES.slice());
      }, logSnapErr('categories')));
      unsubs.push(onSnapshot(doc(db, 'config', locationsDocId), (d) => {
        setLocations(d.exists() ? (d.data().list || []) : DEFAULT_LOCATIONS.slice());
      }, logSnapErr('locations')));

      // Report-like data: only managers (Client + Super Admin) can read these under
      // the Firestore rules, so staff skip subscribing to avoid permission errors.
      if (isManager) {
        unsubs.push(onSnapshot(query(collection(db, 'movements'), where('ownerId', '==', ownerId)), (snap) => {
          setMovements(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('movements')));
        unsubs.push(onSnapshot(query(collection(db, 'deliveryStatus'), where('ownerId', '==', ownerId)), (snap) => {
          const map = {};
          snap.docs.forEach((d) => { map[d.id] = d.data(); });
          setDeliveryStatuses(map);
        }, logSnapErr('deliveryStatus')));
        // Super Admin has no sales report access at all per policy - skip
        // the subscription entirely rather than just hiding it in the UI.
        if (myRole !== 'superadmin') {
          unsubs.push(onSnapshot(query(collection(db, 'sales'), where('ownerId', '==', ownerId)), (snap) => {
            setSales(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
          }, logSnapErr('sales-manager')));
        } else {
          setSales([]);
        }
        unsubs.push(onSnapshot(query(collection(db, 'orders'), where('ownerId', '==', ownerId)), (snap) => {
          setOrders(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.orderDate - a.orderDate));
        }, logSnapErr('orders')));
        // Super Admin monitors login activity platform-wide; a Client only
        // sees activity for their own tenant (themselves + their staff).
        const logsQuery = myRole === 'superadmin'
          ? collection(db, 'loginLogs')
          : query(collection(db, 'loginLogs'), where('ownerId', '==', ownerId));
        unsubs.push(onSnapshot(logsQuery, (snap) => {
          setLoginLogs(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('loginLogs')));
      } else {
        setMovements([]);
        setDeliveryStatuses({});
        setLoginLogs([]);
        setOrders([]);
        // Staff only ever see their own sales - the query itself (not just the
        // rule) scopes this, so there's no risk of over-fetching then hiding.
        unsubs.push(onSnapshot(query(collection(db, 'sales'), where('cashierId', '==', user.uid)), (snap) => {
          setSales(snap.docs.map((d) => ({ id: d.id, ...d.data() })).sort((a, b) => b.timestamp - a.timestamp));
        }, logSnapErr('sales-staff')));
      }

      setLoaded(true);
    })();

    return () => { cancelled = true; unsubs.forEach((u) => u()); };
  }, [user, myProfile?.approved, isManager, ownerId, myRole]);

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 2400);
  };

  // Extends the same tenant-scoped, already-permissioned loginLogs
  // collection to cover the full activity vocabulary (not just login/
  // logout) - staff creation, inventory changes, price/markup changes,
  // sales, and report generation. One shared shape keeps Activity Log's
  // filters simple: every entry has {type, meta, uid, email, timestamp,
  // ownerId}.
  const logActivity = async (type, meta = {}) => {
    if (!ownerId || !user) return;
    try {
      const logId = 'l' + Math.random().toString(36).slice(2, 9);
      await setDoc(doc(db, 'loginLogs', logId), {
        uid: user.uid, email: user.email || '', type, meta, timestamp: Date.now(), ownerId,
      });
    } catch (e) {
      console.error('Activity log error:', e);
    }
  };

  const saveItem = async (draft) => {
    if (!can(myRole, 'editInventory')) { showToast("You don't have permission to edit inventory"); return; }
    const isNew = !draft.id;
    const id = draft.id || ('i' + Math.random().toString(36).slice(2, 9));
    const holderId = draft.holderId || ownerId;
    const unitCost = Math.max(0, Number(draft.unitCost) || 0);
    const markupType = draft.markupType === 'fixed' ? 'fixed' : 'percent';
    const markupValue = Math.max(0, Number(draft.markupValue) || 0);
    const sellingPrice = computeSellingPrice(unitCost, markupType, markupValue);
    const previous = isNew ? null : items.find((i) => i.id === id);
    try {
      await setDoc(doc(db, 'items', id), { ...draft, id, ownerId, holderId, unitCost, markupType, markupValue, sellingPrice });
      if (isNew) {
        playAddSound();
        logActivity('inventory_added', { itemSku: draft.sku, itemName: draft.name });
      } else if (previous && previous.unitCost !== unitCost) {
        logActivity('price_changed', { itemSku: draft.sku, oldCost: previous.unitCost, newCost: unitCost });
      } else {
        logActivity('inventory_edited', { itemSku: draft.sku, itemName: draft.name });
      }
      showToast(draft.id ? `Updated ${draft.sku}` : `Added ${draft.sku} to the manifest`);
    } catch (e) {
      showToast('Could not save item — check your connection');
    }
    setItemModal(null);
  };

  const deleteItem = async (id) => {
    if (!can(myRole, 'deleteInventory')) { showToast("You don't have permission to delete inventory"); return; }
    const it = items.find((i) => i.id === id);
    try {
      await deleteDoc(doc(db, 'items', id));
      const related = movements.filter((m) => m.itemId === id);
      await Promise.all(related.map((m) => deleteDoc(doc(db, 'movements', m.id))));
      try { await deleteDoc(doc(db, 'deliveryStatus', id)); } catch {}
      showToast(`Removed ${it?.sku || 'item'} from the manifest`);
    } catch (e) {
      showToast('Could not remove item — check your connection');
    }
    setConfirmModal(null);
  };

  // Transfers stock out of the Client Admin's own master inventory into a
  // specific staff member's own separate inventory (a real stock movement,
  // logged on both sides) - or, if that staff member already has their own
  // copy of this item (tracked via sourceItemId), tops it up instead of
  // creating a duplicate line. The staff member's copy gets its own
  // independent quantity and starts with no markup - they set their own
  // from there.
  // Assigns a whole batch of items to one staff member in a single action -
  // each line gets its own quantity/base cost, transferred out of the
  // admin's own stock and into (or topped up in) that staff member's own
  // separate inventory, with movements logged on both sides for every line.
  const assignInventoryToStaff = async (staffUid, lines) => {
    if (!can(myRole, 'editInventory')) { showToast("You don't have permission to assign inventory"); return; }
    const staff = approvedUsers.find((u) => u.id === staffUid);
    if (!staff || !lines || lines.length === 0) { showToast('Pick a staff member and at least one item'); return; }

    const now = Date.now();
    let successCount = 0;
    const failedSkus = [];

    for (const line of lines) {
      const source = items.find((i) => i.id === line.itemId);
      const qty = Math.max(1, Number(line.quantity) || 0);
      if (!source || qty > source.quantity) {
        failedSkus.push(source?.sku || line.itemId);
        continue;
      }
      const cost = Math.max(0, Number(line.unitCost) || 0) || source.unitCost;
      const existing = items.find((i) => i.holderId === staffUid && i.sourceItemId === source.id);

      try {
        await setDoc(doc(db, 'items', source.id), { ...source, quantity: source.quantity - qty });

        let staffItemId;
        if (existing) {
          staffItemId = existing.id;
          await setDoc(doc(db, 'items', existing.id), {
            ...existing, quantity: existing.quantity + qty, unitCost: cost,
            sellingPrice: computeSellingPrice(cost, existing.markupType || 'percent', existing.markupValue || 0),
          });
        } else {
          staffItemId = 'i' + Math.random().toString(36).slice(2, 9);
          const markupType = 'percent';
          const markupValue = 0;
          await setDoc(doc(db, 'items', staffItemId), {
            id: staffItemId, ownerId, holderId: staffUid, sourceItemId: source.id,
            sku: source.sku, name: source.name, category: source.category,
            quantity: qty, reorderPoint: source.reorderPoint, unitCost: cost,
            location: source.location, supplierIds: getSupplierIds(source),
            markupType, markupValue, sellingPrice: computeSellingPrice(cost, markupType, markupValue),
          });
        }

        const mvOut = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvOut), {
          id: mvOut, itemId: source.id, type: 'out', qty,
          reason: `Assigned to ${staff.fullName || staff.email}`, timestamp: now, ownerId,
        });
        const mvIn = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvIn), {
          id: mvIn, itemId: staffItemId, type: 'in', qty,
          reason: 'Received from Client Admin', timestamp: now, ownerId,
        });

        logActivity('inventory_assigned', { itemSku: source.sku, itemName: source.name, qty, targetEmail: staff.email });
        successCount++;
      } catch (e) {
        failedSkus.push(source.sku);
      }
    }

    if (successCount > 0) playAddSound();
    if (failedSkus.length === 0) {
      showToast(`Assigned ${successCount} item${successCount === 1 ? '' : 's'} to ${staff.fullName || staff.email}`);
    } else {
      showToast(`Assigned ${successCount} item(s); couldn't assign: ${failedSkus.join(', ')}`);
    }
    setAssignModal(null);
  };

  // Staff can only ever touch the markup on their OWN assigned items - base
  // cost, quantity, SKU, and everything else stays admin-controlled. Also
  // usable by a manager adjusting markup directly, since it's just a subset
  // of what saveItem already allows them.
  const updateMarkup = async (item, markupType, markupValue) => {
    const isOwnItem = item.holderId === user.uid;
    if (!isOwnItem && !can(myRole, 'editInventory')) {
      showToast("You don't have permission to edit this item");
      return;
    }
    const mt = markupType === 'fixed' ? 'fixed' : 'percent';
    const mv = Math.max(0, Number(markupValue) || 0);
    const sellingPrice = computeSellingPrice(item.unitCost, mt, mv);
    try {
      await setDoc(doc(db, 'items', item.id), { markupType: mt, markupValue: mv, sellingPrice }, { merge: true });
      logActivity('markup_changed', { itemSku: item.sku, itemName: item.name, markupType: mt, markupValue: mv });
      showToast(`Markup updated for ${item.sku}`);
    } catch (e) {
      showToast('Could not update markup — check your connection');
    }
    setMarkupModal(null);
  };

  const saveSupplier = async (draft) => {
    if (!can(myRole, 'manageSuppliers')) { showToast("You don't have permission to manage suppliers"); return; }
    const id = draft.id || ('s' + Math.random().toString(36).slice(2, 9));
    try {
      await setDoc(doc(db, 'suppliers', id), { ...draft, id, ownerId });
      if (!draft.id) playAddSound();
      showToast(draft.id ? `Updated ${draft.name}` : `Added ${draft.name} to suppliers`);
    } catch (e) {
      showToast('Could not save supplier — check your connection');
    }
    setSupplierModal(null);
  };

  const deleteSupplier = async (id) => {
    if (!can(myRole, 'manageSuppliers')) { showToast("You don't have permission to manage suppliers"); return; }
    const s = suppliers.find((x) => x.id === id);
    try {
      await deleteDoc(doc(db, 'suppliers', id));
      const affected = items.filter((it) => getSupplierIds(it).includes(id));
      await Promise.all(affected.map((it) => setDoc(doc(db, 'items', it.id), {
        ...it, supplierIds: getSupplierIds(it).filter((sid) => sid !== id),
      })));
      showToast(`Removed ${s?.name || 'supplier'}`);
    } catch (e) {
      showToast('Could not remove supplier — check your connection');
    }
    setConfirmModal(null);
  };

  const addCategory = async (name) => {
    if (!can(myRole, 'manageCategories')) { showToast("You don't have permission to manage categories"); return; }
    const trimmed = name.trim();
    if (!trimmed) return;
    if (categories.some((c) => c.toLowerCase() === trimmed.toLowerCase())) {
      showToast(`"${trimmed}" already exists`);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'categories_' + ownerId), { list: [...categories, trimmed], ownerId });
      playAddSound();
      showToast(`Added category "${trimmed}"`);
    } catch (e) {
      showToast('Could not add category — check your connection');
    }
  };

  const deleteCategory = async (name) => {
    if (!can(myRole, 'manageCategories')) { showToast("You don't have permission to manage categories"); return; }
    const inUse = items.filter((it) => it.category === name).length;
    if (inUse > 0) {
      showToast(`Can't remove "${name}" — ${inUse} item${inUse === 1 ? '' : 's'} still use it`);
      setConfirmModal(null);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'categories_' + ownerId), { list: categories.filter((c) => c !== name), ownerId });
      showToast(`Removed category "${name}"`);
    } catch (e) {
      showToast('Could not remove category — check your connection');
    }
    setConfirmModal(null);
  };

  const updateDeliveryStatus = async (itemId, status, note, orderDate) => {
    if (!can(myRole, 'viewReports')) { showToast("You don't have permission to update delivery status"); return; }
    try {
      await setDoc(doc(db, 'deliveryStatus', itemId), {
        status, note: note || '', orderDate: orderDate || null, updatedAt: Date.now(), ownerId,
      });
      showToast(`Delivery status set to "${status}"`);
    } catch (e) {
      showToast('Could not update delivery status — check your connection');
    }
    setDeliveryStatusModal(null);
  };

  const clearDeliveryStatus = async (itemId) => {
    if (!can(myRole, 'viewReports')) { showToast("You don't have permission to update delivery status"); return; }
    try {
      await deleteDoc(doc(db, 'deliveryStatus', itemId));
      showToast('Reverted to automatic status');
    } catch (e) {
      showToast('Could not clear delivery status — check your connection');
    }
    setDeliveryStatusModal(null);
  };

  const addLocation = async (name) => {
    if (!can(myRole, 'manageLocations')) { showToast("You don't have permission to manage locations"); return; }
    const trimmed = name.trim();
    if (!trimmed) return;
    if (locations.some((l) => l.toLowerCase() === trimmed.toLowerCase())) {
      showToast(`"${trimmed}" already exists`);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'locations_' + ownerId), { list: [...locations, trimmed], ownerId });
      playAddSound();
      showToast(`Added location "${trimmed}"`);
    } catch (e) {
      showToast('Could not add location — check your connection');
    }
  };

  const deleteLocation = async (name) => {
    if (!can(myRole, 'manageLocations')) { showToast("You don't have permission to manage locations"); return; }
    const inUse = items.filter((it) => it.location === name).length;
    if (inUse > 0) {
      showToast(`Can't remove "${name}" — ${inUse} item${inUse === 1 ? '' : 's'} still use it`);
      setConfirmModal(null);
      return;
    }
    try {
      await setDoc(doc(db, 'config', 'locations_' + ownerId), { list: locations.filter((l) => l !== name), ownerId });
      showToast(`Removed location "${name}"`);
    } catch (e) {
      showToast('Could not remove location — check your connection');
    }
    setConfirmModal(null);
  };

  const recordMovement = async (itemId, type, qty, reason) => {
    if (type === 'in' && !can(myRole, 'stockReceive')) { showToast("You don't have permission to receive stock"); return; }
    if (type === 'out' && !can(myRole, 'stockIssue')) { showToast("You don't have permission to issue stock"); return; }
    const item = items.find((i) => i.id === itemId);
    if (!item) return;
    const delta = type === 'in' ? qty : -qty;
    const newQty = Math.max(0, item.quantity + delta);
    const mvId = 'm' + Math.random().toString(36).slice(2, 9);
    try {
      await setDoc(doc(db, 'items', itemId), { ...item, quantity: newQty });
      await setDoc(doc(db, 'movements', mvId), {
        id: mvId, itemId, type, qty,
        reason: reason || (type === 'in' ? 'Stock received' : 'Stock issued'),
        timestamp: Date.now(), ownerId,
      });
      showToast(`${type === 'in' ? 'Received' : 'Issued'} ${qty} × ${item.sku}`);
    } catch (e) {
      showToast('Could not record movement — check your connection');
    }
    setMoveModal(null);
  };

  const completeSale = async (cartLines) => {
    if (cartLines.length === 0) return;
    for (const line of cartLines) {
      const item = items.find((i) => i.id === line.itemId);
      if (!item || line.qty > item.quantity) {
        showToast(`Not enough stock for ${item ? item.sku : 'item'}`);
        return;
      }
    }
    const receiptNo = 'R' + Date.now().toString(36).toUpperCase();
    const now = Date.now();
    const saleLines = cartLines.map((line) => {
      const item = items.find((i) => i.id === line.itemId);
      // Fall back to unitCost for items saved before markup/pricing existed
      // (they've never had a sellingPrice computed and stored yet).
      const price = item.sellingPrice ?? item.unitCost;
      const cost = item.unitCost;
      return {
        itemId: item.id, sku: item.sku, name: item.name,
        qty: line.qty, unitPrice: price, unitCost: cost,
        lineTotal: price * line.qty, lineProfit: (price - cost) * line.qty,
      };
    });
    const subtotal = saleLines.reduce((s, l) => s + l.lineTotal, 0);
    const totalCost = saleLines.reduce((s, l) => s + l.unitCost * l.qty, 0);
    const totalProfit = saleLines.reduce((s, l) => s + l.lineProfit, 0);
    const total = subtotal;
    const sale = {
      id: 's' + Math.random().toString(36).slice(2, 9), receiptNo, timestamp: now, items: saleLines,
      subtotal, total, totalCost, totalProfit, cashierId: user.uid, cashierEmail: user.email || '', ownerId,
    };

    try {
      await Promise.all(cartLines.map((line) => {
        const item = items.find((i) => i.id === line.itemId);
        return setDoc(doc(db, 'items', line.itemId), { ...item, quantity: item.quantity - line.qty });
      }));
      await Promise.all(cartLines.map((line) => {
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        return setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: line.itemId, type: 'out', qty: line.qty,
          reason: `Sale ${receiptNo}`, timestamp: now, ownerId,
        });
      }));
      await setDoc(doc(db, 'sales', sale.id), sale);
      playSaleSound();
      logActivity('sale_completed', { receiptNo, total, itemCount: saleLines.length });
      showToast(`Sale ${receiptNo} recorded — ${currency(total)}`);
      return sale;
    } catch (e) {
      showToast('Could not complete sale — check your connection');
    }
  };

  const cancelSale = async (sale) => {
    if (!can(myRole, 'cancelSales')) { showToast("You don't have permission to cancel sales"); return; }
    if (sale.cancelled) { showToast('This sale is already cancelled'); return; }
    const now = Date.now();
    try {
      await Promise.all(sale.items.map((line) => {
        const item = items.find((i) => i.id === line.itemId);
        if (!item) return Promise.resolve(); // item was deleted since the sale; nothing to restore
        return setDoc(doc(db, 'items', line.itemId), { ...item, quantity: item.quantity + line.qty });
      }));
      await Promise.all(sale.items.map((line) => {
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        return setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: line.itemId, type: 'in', qty: line.qty,
          reason: `Sale ${sale.receiptNo} cancelled`, timestamp: now, ownerId,
        });
      }));
      await setDoc(doc(db, 'sales', sale.id), {
        cancelled: true, cancelledAt: now, cancelledBy: user.email || user.uid,
      }, { merge: true });
      showToast(`Sale ${sale.receiptNo} cancelled — stock restored`);
    } catch (e) {
      showToast('Could not cancel sale — check your connection');
    }
    setConfirmModal(null);
  };

  const saveOrder = async (draft) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    const item = items.find((i) => i.id === draft.itemId);
    const supplier = suppliers.find((s) => s.id === draft.supplierId);
    if (!item || !supplier) { showToast('Pick an item and one of its suppliers'); return; }
    const quantity = Math.max(1, Number(draft.quantity) || 0);
    const unitCost = Math.max(0, Number(draft.unitCost) || 0);
    const now = Date.now();
    const id = 'o' + Math.random().toString(36).slice(2, 9);
    const order = {
      id, ownerId,
      itemId: item.id, itemSku: item.sku, itemName: item.name,
      supplierId: supplier.id, supplierName: supplier.name,
      quantity, unitCost, totalCost: quantity * unitCost,
      status: 'pending',
      orderDate: now,
      expectedDate: now + (supplier.leadTimeDays || 0) * DAY_MS,
      receivedDate: null,
      notes: (draft.notes || '').trim(),
      createdBy: user.uid, createdByEmail: user.email || '',
    };
    try {
      await setDoc(doc(db, 'orders', id), order);
      playAddSound();
      showToast(`Order placed with ${supplier.name}`);
    } catch (e) {
      showToast('Could not place order — check your connection');
    }
    setOrderModal(null);
  };

  const receiveOrder = async (order) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    if (order.status !== 'pending') { showToast(`This order is already ${order.status}`); return; }
    const item = items.find((i) => i.id === order.itemId);
    const now = Date.now();
    try {
      if (item) {
        await setDoc(doc(db, 'items', item.id), { ...item, quantity: item.quantity + order.quantity });
        const mvId = 'm' + Math.random().toString(36).slice(2, 9);
        await setDoc(doc(db, 'movements', mvId), {
          id: mvId, itemId: item.id, type: 'in', qty: order.quantity,
          reason: `Order received from ${order.supplierName}`, timestamp: now, ownerId,
        });
      }
      await setDoc(doc(db, 'orders', order.id), { status: 'received', receivedDate: now }, { merge: true });
      showToast(item ? `Order received — ${order.quantity} × ${order.itemSku} added to stock` : 'Order marked received');
    } catch (e) {
      showToast('Could not mark order received — check your connection');
    }
  };

  const cancelOrder = async (order) => {
    if (!can(myRole, 'manageOrders')) { showToast("You don't have permission to manage orders"); return; }
    if (order.status !== 'pending') { showToast(`This order is already ${order.status}`); return; }
    try {
      await setDoc(doc(db, 'orders', order.id), {
        status: 'cancelled', cancelledAt: Date.now(), cancelledBy: user.email || user.uid,
      }, { merge: true });
      showToast(`Order for ${order.itemSku} cancelled`);
    } catch (e) {
      showToast('Could not cancel order — check your connection');
    }
    setConfirmModal(null);
  };

  // Staff's `items` state is already query-scoped to just their own holderId
  // (see the data-loading effect), so it needs no further filtering here.
  // A manager's `items` state includes the WHOLE tenant (their own master
  // inventory + everything assigned to every staff member) - "my own
  // inventory" for a manager means just the items they still personally
  // hold, i.e. haven't assigned out. Legacy items from before this feature
  // (no holderId yet) default to counting as the admin's own.
  const myOwnItems = useMemo(() => {
    if (myRole === 'staff') return items;
    return items.filter((it) => !it.holderId || it.holderId === ownerId);
  }, [items, myRole, ownerId]);

  const filtered = useMemo(() => {
    let list = myOwnItems.filter((it) => {
      const matchesSearch =
        it.name.toLowerCase().includes(search.toLowerCase()) ||
        it.sku.toLowerCase().includes(search.toLowerCase());
      const matchesCat = categoryFilter === 'All' || it.category === categoryFilter;
      return matchesSearch && matchesCat;
    });
    list.sort((a, b) => {
      if (sortKey === 'name') return a.name.localeCompare(b.name);
      if (sortKey === 'qty') return b.quantity - a.quantity;
      if (sortKey === 'value') return b.quantity * b.unitCost - a.quantity * a.unitCost;
      if (sortKey === 'low') return (a.quantity - a.reorderPoint) - (b.quantity - b.reorderPoint);
      return 0;
    });
    return list;
  }, [myOwnItems, search, categoryFilter, sortKey]);

  const totals = useMemo(() => {
    const totalUnits = myOwnItems.reduce((s, i) => s + i.quantity, 0);
    const totalValue = myOwnItems.reduce((s, i) => s + i.quantity * i.unitCost, 0);
    const lowStock = myOwnItems.filter((i) => i.quantity <= i.reorderPoint);
    return { totalSkus: myOwnItems.length, totalUnits, totalValue, lowStock };
  }, [items]);

  const categoryData = useMemo(() => {
    return categories.map((cat) => ({
      category: cat.split(' ')[0],
      units: myOwnItems.filter((i) => i.category === cat).reduce((s, i) => s + i.quantity, 0),
    })).filter((c) => c.units > 0);
  }, [myOwnItems, categories]);

  // Profit is derived entirely from completed (non-cancelled) sales, which
  // already carry a cost/profit snapshot per line from the moment they were
  // rung up - so re-pricing an item later never rewrites history here.
  const profitStats = useMemo(() => {
    const completed = sales.filter((s) => !s.cancelled);
    const totalRevenue = completed.reduce((s, sale) => s + (sale.total ?? 0), 0);
    const totalCost = completed.reduce((s, sale) => s + (sale.totalCost ?? 0), 0);
    const totalProfit = completed.reduce((s, sale) => s + (sale.totalProfit ?? (sale.total ?? 0) - (sale.totalCost ?? 0)), 0);
    const margin = totalRevenue > 0 ? (totalProfit / totalRevenue) * 100 : 0;

    const byItem = {};
    completed.forEach((sale) => {
      (sale.items || []).forEach((line) => {
        if (!byItem[line.itemId]) byItem[line.itemId] = { itemId: line.itemId, sku: line.sku, name: line.name, qty: 0, profit: 0 };
        byItem[line.itemId].qty += line.qty;
        byItem[line.itemId].profit += line.lineProfit ?? ((line.unitPrice ?? 0) - (line.unitCost ?? 0)) * line.qty;
      });
    });
    const profitByItem = Object.values(byItem).sort((a, b) => b.profit - a.profit);

    const perSale = completed
      .slice(0, 8)
      .map((s) => ({
        id: s.id, receiptNo: s.receiptNo, timestamp: s.timestamp,
        revenue: s.total ?? 0, cost: s.totalCost ?? 0,
        profit: s.totalProfit ?? (s.total ?? 0) - (s.totalCost ?? 0),
      }));

    return { totalRevenue, totalCost, totalProfit, margin, profitByItem, perSale };
  }, [sales]);

  const filteredMovements = useMemo(() => {
    return movements.filter((m) => {
      const item = items.find((i) => i.id === m.itemId);
      const matchesSearch =
        !histSearch ||
        (item && (item.sku.toLowerCase().includes(histSearch.toLowerCase()) || item.name.toLowerCase().includes(histSearch.toLowerCase()))) ||
        m.reason.toLowerCase().includes(histSearch.toLowerCase());
      const matchesType = histType === 'All' || m.type === histType.toLowerCase();
      const matchesItem = histItem === 'All' || m.itemId === histItem;
      return matchesSearch && matchesType && matchesItem;
    });
  }, [movements, items, histSearch, histType, histItem]);

  const deliveryRows = useMemo(() => {
    const rows = [];
    myOwnItems.forEach((it) => {
      getSupplierIds(it).forEach((sid) => {
        const supplier = suppliers.find((s) => s.id === sid);
        if (!supplier) return;
        const inbound = movements
          .filter((m) => m.itemId === it.id && m.type === 'in')
          .sort((a, b) => b.timestamp - a.timestamp);
        const lastDelivery = inbound.length ? inbound[0].timestamp : null;
        const lastDeliveryQty = inbound.length ? inbound[0].qty : null;
        const expectedNext = lastDelivery ? lastDelivery + supplier.leadTimeDays * DAY_MS : null;
        const overdue = expectedNext && expectedNext < Date.now() && it.quantity <= it.reorderPoint;
        const autoStatus = it.quantity <= it.reorderPoint ? (overdue ? 'Delivery Overdue' : 'Reorder Now') : 'On Track';
        // A manual status override is set per-item (not per-supplier) - if an
        // item has more than one supplier, both rows share the same override.
        const override = deliveryStatuses[it.id];
        const status = override ? override.status : autoStatus;
        rows.push({
          item: it, supplier, lastDelivery, lastDeliveryQty, expectedNext, status, autoStatus,
          manual: !!override, note: override?.note || '', orderDate: override?.orderDate || null,
          log: inbound, // full delivery history for this item, most recent first
        });
      });
    });
    return rows;
  }, [myOwnItems, suppliers, movements, deliveryStatuses]);

  const supplierMap = useMemo(() => Object.fromEntries(suppliers.map((s) => [s.id, s])), [suppliers]);

  if (!authChecked) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          LOADING…
        </div>
      </div>
    );
  }

  if (!user) {
    return <LoginScreen logo={effectiveLogo} theme={activeTheme} />;
  }

  if (!profileChecked) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          CHECKING YOUR ACCOUNT…
        </div>
      </div>
    );
  }

  if (!myProfile || !myProfile.approved) {
    return <PendingApprovalScreen email={user.email} missingProfile={!myProfile} onSignOut={handleSignOut} />;
  }

  if (!loaded) {
    return (
      <div style={{ ...styles.wrap, alignItems: 'center', justifyContent: 'center', display: 'flex' }}>
        <style>{FONT_IMPORT}</style>
        <div style={{ fontFamily: "'Quicksand', sans-serif", color: 'var(--line)', letterSpacing: '0.08em' }}>
          LOADING MANIFEST…
        </div>
      </div>
    );
  }

  return (
    <div style={styles.wrap} className="depot-wrap">
      <style>{`
        ${FONT_IMPORT}
        ${RESPONSIVE_CSS}
        :root {
          ${themeCssVars(activeTheme)}
        }
        * { box-sizing: border-box; }
        .depot-btn { cursor: pointer; border: none; font-family: 'Nunito', sans-serif; transition: all 0.15s ease; }
        .depot-btn:active { transform: translateY(1px); }
        .depot-row:hover { background: rgba(15,42,71,0.04); }
        .depot-input:focus, .depot-select:focus { outline: 2px solid var(--blueprint); outline-offset: 1px; }
        .depot-scroll::-webkit-scrollbar { width: 8px; height: 8px; }
        .depot-scroll::-webkit-scrollbar-thumb { background: var(--line-dim); border-radius: 4px; }
        @keyframes slideUp { from { opacity: 0; transform: translateY(8px);} to { opacity:1; transform:translateY(0);} }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        @media print {
          .depot-sidebar, .depot-no-print { display: none !important; }
          .depot-main { padding: 0 !important; overflow: visible !important; }
          .depot-print-title { display: block !important; }
          body { background: #fff !important; }
        }
      `}</style>

      <BackgroundDecor variant="app" />

      <Sidebar view={view} setView={setView} lowCount={totals.lowStock.length} role={myRole} pendingCount={pendingUsers.length} logo={effectiveLogo} onSignOut={handleSignOut} />

      <main style={styles.main} className="depot-scroll depot-main">
        <TopBar
          view={view}
          role={myRole}
          onAdd={() => {
            if (view === 'inventory') setItemModal('new');
            if (view === 'suppliers') setSupplierModal('new');
            if (view === 'orders') setOrderModal('new');
          }}
        />

        {!canAccessView(myRole, view) ? (
          <AccessDenied />
        ) : (
        <>
        {view === 'overview' && (
          <Overview totals={totals} categoryData={categoryData} profitStats={profitStats} role={myRole} onQuickMove={(it) => setMoveModal(it)} />
        )}

        {view === 'inventory' && (
          <InventoryView
            filtered={filtered}
            supplierMap={supplierMap}
            categories={categories}
            role={myRole}
            search={search} setSearch={setSearch}
            categoryFilter={categoryFilter} setCategoryFilter={setCategoryFilter}
            sortKey={sortKey} setSortKey={setSortKey}
            onEdit={(it) => setItemModal(it)}
            onDelete={(it) => setConfirmModal({ kind: 'item', target: it })}
            onMove={(it) => setMoveModal(it)}
            onEditMarkup={(it) => setMarkupModal(it)}
          />
        )}

        {view === 'staffInventory' && (
          <StaffInventoryView
            items={items}
            staffList={approvedUsers.filter((u) => u.role === 'staff')}
            selectedStaffUid={selectedStaffUid}
            setSelectedStaffUid={setSelectedStaffUid}
            onAssign={() => setAssignModal(true)}
            onEdit={(it) => setItemModal(it)}
            onDelete={(it) => setConfirmModal({ kind: 'item', target: it })}
            onMove={(it) => setMoveModal(it)}
          />
        )}

        {view === 'suppliers' && (
          <SuppliersView
            suppliers={suppliers}
            items={items}
            onEdit={(s) => setSupplierModal(s)}
            onDelete={(s) => setConfirmModal({ kind: 'supplier', target: s })}
          />
        )}

        {view === 'orders' && (
          <OrdersView
            orders={orders}
            onReceive={receiveOrder}
            onCancel={(o) => setConfirmModal({ kind: 'order', target: o })}
          />
        )}

        {view === 'categories' && (
          <CategoriesView
            categories={categories}
            items={items}
            onAdd={addCategory}
            onDelete={(name) => setConfirmModal({ kind: 'category', target: { name } })}
          />
        )}

        {view === 'locations' && (
          <LocationsView
            locations={locations}
            items={items}
            onAdd={addLocation}
            onDelete={(name) => setConfirmModal({ kind: 'location', target: { name } })}
          />
        )}

        {view === 'delivery' && (
          <DeliveryTimesView
            rows={deliveryRows}
            onUpdateStatus={(row) => setDeliveryStatusModal(row)}
            onViewHistory={(itemId) => {
              setHistItem(itemId);
              setHistSearch('');
              setHistType('All');
              setView('history');
            }}
          />
        )}

        {view === 'pos' && (
          <POSView items={items} onCompleteSale={completeSale} />
        )}

        {view === 'sales' && (
          <SalesHistoryView sales={sales} role={myRole} onCancelSale={(sale) => setConfirmModal({ kind: 'sale', target: sale })} onLogActivity={logActivity} />
        )}

        {view === 'mysales' && (
          <MySalesView sales={sales} />
        )}

        {view === 'history' && (
          <TransactionHistoryView
            movements={filteredMovements}
            items={items}
            histSearch={histSearch} setHistSearch={setHistSearch}
            histType={histType} setHistType={setHistType}
            histItem={histItem} setHistItem={setHistItem}
          />
        )}

        {view === 'approvals' && (
          <TeamAccessView
            pendingUsers={pendingUsers}
            approvedUsers={approvedUsers}
            currentUid={user.uid}
            myRole={myRole}
            canCreateStaff={can(myRole, 'createStaff')}
            onCreateStaff={createStaffAccount}
            onApprove={approveUser}
            onDeny={denyUser}
            onRevoke={revokeUser}
            onChangeRole={changeUserRole}
            onSaveProfile={updateUserProfile}
            branding={effectiveBranding}
            onSaveLogo={saveLogo}
            onResetLogo={resetLogo}
            onSetTheme={setThemeKey}
          />
        )}

        {view === 'activity' && (
          <ActivityLogView logs={loginLogs} myRole={myRole} approvedUsers={approvedUsers} pendingUsers={pendingUsers} />
        )}

        {view === 'myprofile' && (
          <MyProfileView profile={myProfile} uid={user.uid} onSave={updateUserProfile} onChangePassword={changePassword} />
        )}
        </>
        )}
      </main>

      {itemModal && (
        <ItemModal
          draft={itemModal === 'new' ? null : itemModal}
          suppliers={suppliers}
          categories={categories}
          locations={locations}
          onClose={() => setItemModal(null)}
          onSave={saveItem}
        />
      )}

      {moveModal && (
        <MoveModal item={moveModal} allowIssue={can(myRole, 'stockIssue')} onClose={() => setMoveModal(null)} onSubmit={recordMovement} />
      )}

      {deliveryStatusModal && (
        <DeliveryStatusModal
          row={deliveryStatusModal}
          onClose={() => setDeliveryStatusModal(null)}
          onSave={updateDeliveryStatus}
          onClearOverride={clearDeliveryStatus}
        />
      )}

      {supplierModal && (
        <SupplierModal
          draft={supplierModal === 'new' ? null : supplierModal}
          onClose={() => setSupplierModal(null)}
          onSave={saveSupplier}
        />
      )}

      {orderModal && (
        <OrderModal
          draft={orderModal === 'new' ? null : orderModal}
          items={items}
          suppliers={suppliers}
          onClose={() => setOrderModal(null)}
          onSave={saveOrder}
        />
      )}

      {assignModal && (
        <AssignInventoryModal
          myOwnItems={myOwnItems}
          staffList={approvedUsers.filter((u) => u.role === 'staff')}
          onClose={() => setAssignModal(null)}
          onSave={assignInventoryToStaff}
        />
      )}

      {markupModal && (
        <MarkupModal
          item={markupModal}
          onClose={() => setMarkupModal(null)}
          onSave={updateMarkup}
        />
      )}

      {confirmModal && confirmModal.kind === 'item' && (
        <ConfirmModal
          title="REMOVE ITEM"
          message={<>Remove <strong>{confirmModal.target.sku} — {confirmModal.target.name}</strong> from the manifest? This also clears its movement history.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteItem(confirmModal.target.id)}
        />
      )}

      {confirmModal && confirmModal.kind === 'supplier' && (
        <ConfirmModal
          title="REMOVE SUPPLIER"
          message={<>Remove <strong>{confirmModal.target.name}</strong>? Items linked to this supplier will be unlinked, not deleted.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteSupplier(confirmModal.target.id)}
        />
      )}

      {confirmModal && confirmModal.kind === 'order' && (
        <ConfirmModal
          title="CANCEL ORDER"
          message={<>Cancel the order for <strong>{confirmModal.target.quantity} × {confirmModal.target.itemSku}</strong> from <strong>{confirmModal.target.supplierName}</strong>? This won't affect stock.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => cancelOrder(confirmModal.target)}
          confirmLabel="Cancel Order"
        />
      )}

      {confirmModal && confirmModal.kind === 'category' && (
        <ConfirmModal
          title="REMOVE CATEGORY"
          message={<>Remove the category <strong>{confirmModal.target.name}</strong>? This only works if no items currently use it.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteCategory(confirmModal.target.name)}
        />
      )}

      {confirmModal && confirmModal.kind === 'location' && (
        <ConfirmModal
          title="REMOVE LOCATION"
          message={<>Remove the location <strong>{confirmModal.target.name}</strong>? This only works if no items currently use it.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => deleteLocation(confirmModal.target.name)}
        />
      )}

      {confirmModal && confirmModal.kind === 'sale' && (
        <ConfirmModal
          title="CANCEL SALE"
          message={<>Cancel sale <strong>{confirmModal.target.receiptNo}</strong> for {currency(confirmModal.target.total)}? This restores the sold quantities back into stock and can't be undone.</>}
          onCancel={() => setConfirmModal(null)}
          onConfirm={() => cancelSale(confirmModal.target)}
          confirmLabel="Cancel Sale"
        />
      )}

      {toast && (
        <div style={styles.toast}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--amber)' }} />
          {toast}
        </div>
      )}
    </div>
  );
}

