function LegalModal({ kind, onClose, theme }) {
  const t = theme || THEMES[DEFAULT_THEME_KEY];
  const sections = kind === 'privacy' ? PRIVACY_SECTIONS : TERMS_SECTIONS;
  const title = kind === 'privacy' ? 'PRIVACY POLICY' : 'TERMS OF SERVICE';
  return (
    <div
      style={{
        position: 'fixed', inset: 0, background: 'rgba(10,20,35,0.55)', display: 'flex',
        alignItems: 'center', justifyContent: 'center', zIndex: 50,
      }}
      onClick={onClose}
    >
      <div
        style={{
          background: '#FFFCF5', borderRadius: 10, width: '90%', maxWidth: 560, maxHeight: '82vh',
          display: 'flex', flexDirection: 'column', boxShadow: '0 20px 60px rgba(0,0,0,0.35)',
          border: `1px solid ${t.lineDim}`, overflow: 'hidden',
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <div style={{
          display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '14px 18px',
          background: t.blueprint, color: '#fff', fontFamily: "'Quicksand', sans-serif",
          fontSize: 12, letterSpacing: '0.08em', fontWeight: 600,
        }}>
          <span>{title}</span>
          <button
            onClick={onClose}
            style={{ background: 'transparent', border: 'none', color: '#fff', width: 24, height: 24, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}
          >
            <X size={16} />
          </button>
        </div>
        <div style={{ padding: 18, overflowY: 'auto' }}>
          <div style={{ fontSize: 11.5, color: 'rgba(59,42,31,0.5)', fontStyle: 'italic', marginBottom: 14 }}>
            This is a general starting-point document and not a substitute for legal advice specific to your business.
          </div>
          {sections.map((s) => (
            <div key={s.title} style={{ marginBottom: 14 }}>
              <div style={{ fontFamily: "'Quicksand', sans-serif", fontWeight: 600, fontSize: 13.5, color: t.ink, marginBottom: 4 }}>{s.title}</div>
              <div style={{ fontSize: 13, color: 'rgba(59,42,31,0.75)', lineHeight: 1.6 }}>{s.body}</div>
            </div>
          ))}
        </div>
        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8, padding: '14px 18px', borderTop: `1px solid ${t.lineDim}` }}>
          <button
            onClick={onClose}
            style={{
              background: t.blueprint, color: '#fff', border: 'none', borderRadius: 6,
              padding: '9px 18px', fontSize: 13, fontWeight: 500, cursor: 'pointer',
            }}
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
}

function LoginScreen({ logo, theme }) {
  const t = theme || THEMES[DEFAULT_THEME_KEY];
  const [mode, setMode] = useState('signin'); // 'signin' | 'signup' | 'reset'
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [username, setUsername] = useState('');
  const [contactNumber, setContactNumber] = useState('');
  const [address, setAddress] = useState('');
  const [agreeTerms, setAgreeTerms] = useState(false);
  const [error, setError] = useState('');
  const [busy, setBusy] = useState(false);
  const [resetSent, setResetSent] = useState(false);
  const [legalModal, setLegalModal] = useState(null); // 'terms' | 'privacy' | null

  const friendlyError = (err) => {
    const code = err?.code || '';
    if (code === 'auth/email-already-in-use') return 'That email already has an account. Try signing in instead.';
    if (code === 'auth/invalid-email') return 'That email address doesn\'t look right.';
    if (code === 'auth/weak-password') return 'Password should be at least 6 characters.';
    if (code === 'auth/user-not-found' || code === 'auth/wrong-password' || code === 'auth/invalid-credential') {
      return 'Sign-in failed. Check your email and password.';
    }
    return mode === 'signup' ? 'Could not create your account. Please try again.' : 'Sign-in failed. Check your email and password.';
  };

  const submit = async (e) => {
    e.preventDefault();
    setError('');

    if (mode === 'signup' && password !== confirmPassword) {
      setError('Passwords don\'t match.');
      return;
    }
    if (mode === 'signup' && !agreeTerms) {
      setError('Please agree to the Terms of Service and Privacy Policy to continue.');
      return;
    }

    setBusy(true);
    try {
      if (mode === 'signup') {
        const cred = await createUserWithEmailAndPassword(auth, email.trim(), password);
        // Written separately from (and merged with) the app's own profile
        // bootstrap effect, so whichever runs first or second, neither wipes
        // the other's fields.
        try {
          // Self-signup always creates a new Client Admin account - i.e. a
          // new tenant/business, still pending a Super Admin's approval.
          // Staff accounts are created *by* a Client Admin from inside the
          // app (Team Access), never through this public form.
          await setDoc(doc(db, 'users', cred.user.uid), {
            email: email.trim(), approved: false, isAdmin: false, role: 'client', createdAt: Date.now(),
            fullName: fullName.trim(), username: username.trim(), contactNumber: contactNumber.trim(),
            address: address.trim(), userIdNumber: generateUserIdNumber(),
            agreedToTermsAt: Date.now(),
          }, { merge: true });
        } catch (profileErr) {
          console.error('Could not save signup profile details:', profileErr);
        }
      } else {
        await signInWithEmailAndPassword(auth, email.trim(), password);
      }
    } catch (err) {
      setError(friendlyError(err));
    } finally {
      setBusy(false);
    }
  };

  const submitReset = async (e) => {
    e.preventDefault();
    setError('');
    setBusy(true);
    try {
      await sendPasswordResetEmail(auth, email.trim());
      setResetSent(true);
    } catch (err) {
      if (err?.code === 'auth/invalid-email') setError('That email address doesn\'t look right.');
      else if (err?.code === 'auth/too-many-requests') setError('Too many attempts — please wait a bit and try again.');
      // Deliberately don't reveal auth/user-not-found - showing the same
      // "sent" confirmation either way avoids leaking which emails have
      // an account.
      else setResetSent(true);
    } finally {
      setBusy(false);
    }
  };

  const switchMode = () => {
    setMode(mode === 'signin' ? 'signup' : 'signin');
    setError('');
    setPassword('');
    setConfirmPassword('');
    setAgreeTerms(false);
  };

  const goToReset = () => {
    setMode('reset');
    setError('');
    setResetSent(false);
  };

  const backToSignIn = () => {
    setMode('signin');
    setError('');
    setResetSent(false);
    setPassword('');
  };

  return (
    <div style={{
      minHeight: '85vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: t.paper, fontFamily: "'Nunito', sans-serif", borderRadius: 8,
      position: 'relative', overflow: 'hidden',
    }}>
      <style>{FONT_IMPORT}{RESPONSIVE_CSS}{`
        @keyframes stockit-float {
          0%, 100% { transform: translateY(0) scale(1); }
          50% { transform: translateY(-6px) scale(1.02); }
        }
        .depot-logo-float { animation: stockit-float 3.6s ease-in-out infinite; }
        @media (prefers-reduced-motion: reduce) {
          .depot-logo-float { animation: none; }
        }
      `}</style>
      <BackgroundDecor variant="login" />
      {mode === 'reset' ? (
        <form onSubmit={submitReset} className="depot-login-form" style={{
          background: '#FFFCF5', padding: '32px 30px', borderRadius: 10, width: 400,
          boxShadow: `0 16px 40px rgba(0,0,0,0.12), 0 0 0 1px ${t.lineDim}`,
          border: `1px solid ${t.lineDim}`, position: 'relative', zIndex: 1,
        }}>
          <div style={{
            background: `linear-gradient(135deg, #FFFCF5 0%, ${t.paper} 100%)`,
            borderRadius: 10, padding: '22px 20px 16px', marginBottom: 20,
            border: `1px solid ${t.lineDim}`,
          }}>
            <img src={logo} alt="RAS logo" className="depot-logo-float" style={{ width: '100%', height: 'auto', display: 'block' }} />
          </div>
          <div style={{ fontFamily: "'Quicksand', sans-serif", fontWeight: 600, fontSize: 20, marginBottom: 4, color: t.ink }}>
            Reset Your Password
          </div>
          {resetSent ? (
            <>
              <div style={{ fontSize: 13, color: 'rgba(59,42,31,0.7)', lineHeight: 1.6, marginBottom: 20 }}>
                If an account exists for <strong>{email.trim()}</strong>, a password reset link has been sent. Check your inbox (and spam folder).
              </div>
              <button type="button" onClick={backToSignIn} style={{
                width: '100%', background: t.blueprint, color: '#fff', border: 'none', borderRadius: 6,
                padding: '10px 0', fontSize: 13.5, fontWeight: 500, cursor: 'pointer',
              }}>
                Back to Sign In
              </button>
            </>
          ) : (
            <>
              <div style={{ fontSize: 12.5, color: 'rgba(59,42,31,0.55)', marginBottom: 20 }}>
                Enter the email on your account and we\u2019ll send you a link to reset your password.
              </div>
              <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Email</label>
              <input
                type="email" required value={email} onChange={(e) => setEmail(e.target.value)}
                style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 16, boxSizing: 'border-box' }}
              />
              {error && <div style={{ fontSize: 12.5, color: t.red, marginBottom: 12 }}>{error}</div>}
              <button type="submit" disabled={busy} style={{
                width: '100%', background: t.blueprint, color: '#fff', border: 'none', borderRadius: 6,
                padding: '10px 0', fontSize: 13.5, fontWeight: 500, cursor: 'pointer', opacity: busy ? 0.6 : 1,
              }}>
                {busy ? 'Sending…' : 'Send Reset Link'}
              </button>
              <div style={{ textAlign: 'center', marginTop: 16, fontSize: 12.5, color: 'rgba(59,42,31,0.6)' }}>
                <button type="button" onClick={backToSignIn} style={{
                  background: 'none', border: 'none', padding: 0, color: t.blueprint, fontWeight: 600,
                  cursor: 'pointer', textDecoration: 'underline', fontSize: 12.5,
                }}>
                  Back to Sign In
                </button>
              </div>
            </>
          )}
        </form>
      ) : (
      <form onSubmit={submit} className="depot-login-form" style={{
        background: '#FFFCF5', padding: '32px 30px', borderRadius: 10, width: 400,
        boxShadow: `0 16px 40px rgba(0,0,0,0.12), 0 0 0 1px ${t.lineDim}`,
        border: `1px solid ${t.lineDim}`, position: 'relative', zIndex: 1,
      }}>
        <div style={{
          background: `linear-gradient(135deg, #FFFCF5 0%, ${t.paper} 100%)`,
          borderRadius: 10, padding: '22px 20px 16px', marginBottom: 20,
          border: `1px solid ${t.lineDim}`,
        }}>
          <img src={logo} alt="RAS logo" className="depot-logo-float" style={{ width: '100%', height: 'auto', display: 'block' }} />
        </div>
        <div style={{ fontFamily: "'Quicksand', sans-serif", fontWeight: 600, fontSize: 20, marginBottom: 4, color: t.ink }}>
          {mode === 'signup' ? 'Create Your Account' : 'Welcome Back!'}
        </div>
        <div style={{ fontSize: 12.5, color: 'rgba(59,42,31,0.55)', marginBottom: 20 }}>
          {mode === 'signup' ? 'Sign up for a RAS Client Account' : 'Sign in to Your RAS Client Account'}
        </div>
        <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Email</label>
        <input
          type="email" required value={email} onChange={(e) => setEmail(e.target.value)}
          style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 14, boxSizing: 'border-box' }}
        />
        <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Password</label>
        <input
          type="password" required value={password} onChange={(e) => setPassword(e.target.value)}
          style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: mode === 'signup' ? 14 : 6, boxSizing: 'border-box' }}
        />
        {mode === 'signin' && (
          <div style={{ textAlign: 'right', marginBottom: 14 }}>
            <button type="button" onClick={goToReset} style={{
              background: 'none', border: 'none', padding: 0, color: t.blueprint,
              cursor: 'pointer', textDecoration: 'underline', fontSize: 11.5,
            }}>
              Forgot password?
            </button>
          </div>
        )}
        {mode === 'signup' && (
          <>
            <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Confirm Password</label>
            <input
              type="password" required value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)}
              style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 16, boxSizing: 'border-box' }}
            />
            <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Full Name</label>
            <input
              type="text" required value={fullName} onChange={(e) => setFullName(e.target.value)}
              style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 14, boxSizing: 'border-box' }}
            />
            <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Username</label>
            <input
              type="text" required value={username} onChange={(e) => setUsername(e.target.value)}
              style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 14, boxSizing: 'border-box' }}
            />
            <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Contact Number</label>
            <input
              type="tel" required value={contactNumber} onChange={(e) => setContactNumber(e.target.value)}
              style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 14, boxSizing: 'border-box' }}
            />
            <label style={{ display: 'block', fontSize: 11, fontWeight: 600, color: 'rgba(59,42,31,0.55)', marginBottom: 5 }}>Address <span style={{ fontWeight: 400 }}>(optional)</span></label>
            <input
              type="text" value={address} onChange={(e) => setAddress(e.target.value)}
              style={{ width: '100%', padding: '9px 11px', borderRadius: 6, border: '1px solid rgba(59,42,31,0.18)', fontSize: 13.5, marginBottom: 16, boxSizing: 'border-box' }}
            />
            <label style={{ display: 'flex', alignItems: 'flex-start', gap: 8, fontSize: 12, color: 'rgba(59,42,31,0.7)', marginBottom: 16, cursor: 'pointer' }}>
              <input type="checkbox" checked={agreeTerms} onChange={(e) => setAgreeTerms(e.target.checked)} style={{ marginTop: 2 }} />
              <span>
                I agree to the{' '}
                <button type="button" onClick={() => setLegalModal('terms')} style={{ background: 'none', border: 'none', padding: 0, color: t.blueprint, fontWeight: 600, cursor: 'pointer', textDecoration: 'underline', fontSize: 12 }}>Terms of Service</button>
                {' '}and{' '}
                <button type="button" onClick={() => setLegalModal('privacy')} style={{ background: 'none', border: 'none', padding: 0, color: t.blueprint, fontWeight: 600, cursor: 'pointer', textDecoration: 'underline', fontSize: 12 }}>Privacy Policy</button>.
              </span>
            </label>
          </>
        )}
        {error && <div style={{ fontSize: 12.5, color: t.red, marginBottom: 12 }}>{error}</div>}
        <button type="submit" disabled={busy} style={{
          width: '100%', background: t.blueprint, color: '#fff', border: 'none', borderRadius: 6,
          padding: '10px 0', fontSize: 13.5, fontWeight: 500, cursor: 'pointer', opacity: busy ? 0.6 : 1,
        }}>
          {busy ? (mode === 'signup' ? 'Creating account…' : 'Signing in…') : (mode === 'signup' ? 'Sign Up' : 'Sign In')}
        </button>
        <div style={{ textAlign: 'center', marginTop: 16, fontSize: 12.5, color: 'rgba(59,42,31,0.6)' }}>
          {mode === 'signup' ? 'Already have an account?' : "Don't have an account?"}{' '}
          <button type="button" onClick={switchMode} style={{
            background: 'none', border: 'none', padding: 0, color: t.blueprint, fontWeight: 600,
            cursor: 'pointer', textDecoration: 'underline', fontSize: 12.5,
          }}>
            {mode === 'signup' ? 'Sign In' : 'Sign Up'}
          </button>
        </div>
        <div style={{ textAlign: 'center', marginTop: 10, fontSize: 11, color: 'rgba(59,42,31,0.45)' }}>
          <button type="button" onClick={() => setLegalModal('terms')} style={{ background: 'none', border: 'none', padding: 0, color: 'inherit', cursor: 'pointer', textDecoration: 'underline', fontSize: 11 }}>Terms of Service</button>
          {' · '}
          <button type="button" onClick={() => setLegalModal('privacy')} style={{ background: 'none', border: 'none', padding: 0, color: 'inherit', cursor: 'pointer', textDecoration: 'underline', fontSize: 11 }}>Privacy Policy</button>
        </div>
      </form>
      )}
      {legalModal && <LegalModal kind={legalModal} onClose={() => setLegalModal(null)} theme={t} />}
    </div>
  );
}

function AccessDenied() {
  return (
    <div style={{ animation: 'fadeIn 0.3s ease', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '60px 20px', textAlign: 'center' }}>
      <div style={{
        width: 56, height: 56, borderRadius: '50%', background: 'var(--red)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: 16,
      }}>
        <AlertTriangle size={28} color="#fff" />
      </div>
      <div style={{ fontFamily: "'Quicksand', sans-serif", fontWeight: 600, fontSize: 19, marginBottom: 6, color: 'var(--ink)' }}>
        Access Denied
      </div>
      <div style={{ fontSize: 13, color: 'rgba(59,42,31,0.6)', maxWidth: 360 }}>
        Your account doesn't have permission to view this page. If you think that's wrong, ask an admin to check your role in Team Access.
      </div>
    </div>
  );
}

function PendingApprovalScreen({ email, missingProfile, onSignOut }) {
  return (
    <div style={{
      minHeight: '85vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: 'var(--paper, #F7EFDD)', fontFamily: "'Nunito', sans-serif", borderRadius: 8,
      position: 'relative', overflow: 'hidden',
    }}>
      <style>{FONT_IMPORT}{RESPONSIVE_CSS}</style>
      <BackgroundDecor variant="login" />
      <div className="depot-login-form" style={{
        background: '#FFFCF5', padding: '32px 30px', borderRadius: 10, width: 380, textAlign: 'center',
        boxShadow: '0 16px 40px rgba(59,42,31,0.12), 0 0 0 1px rgba(217,164,65,0.15)',
        border: '1px solid rgba(217,164,65,0.35)', position: 'relative', zIndex: 1,
      }}>
        <div style={{
          width: 52, height: 52, borderRadius: '50%', background: missingProfile ? 'var(--red, #C1503A)' : 'var(--amber, #D9A441)',
          display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px',
        }}>
          {missingProfile ? <AlertTriangle size={26} color="#fff" /> : <Clock size={26} color="#fff" />}
        </div>
        <div style={{ fontFamily: "'Quicksand', sans-serif", fontWeight: 600, fontSize: 19, marginBottom: 8, color: '#3B2A1F' }}>
          {missingProfile ? "Couldn't Set Up Your Account" : 'Awaiting Approval'}
        </div>
        {missingProfile ? (
          <div style={{ fontSize: 13, color: 'rgba(59,42,31,0.65)', lineHeight: 1.6, marginBottom: 4 }}>
            Your login (<strong>{email}</strong>) worked, but the app couldn't create your account profile in the database. This usually means the Firestore security rules haven't been published yet, or don't match what this app expects. Try again below, or check the browser console (F12) for the exact error.
          </div>
        ) : (
          <div style={{ fontSize: 13, color: 'rgba(59,42,31,0.65)', lineHeight: 1.6, marginBottom: 4 }}>
            Your account (<strong>{email}</strong>) has been created, but an administrator needs to approve it before you can access Stock It.
          </div>
        )}
        <div style={{ fontSize: 12, color: 'rgba(59,42,31,0.5)', marginTop: 10, marginBottom: 22 }}>
          {missingProfile ? 'Retrying will attempt to create your profile again.' : "This page will update automatically once you're approved — no need to refresh."}
        </div>
        {missingProfile && (
          <button
            onClick={() => window.location.reload()}
            style={{
              width: '100%', background: '#2F4A32', color: '#fff', border: 'none',
              borderRadius: 6, padding: '10px 0', fontSize: 13.5, fontWeight: 500, cursor: 'pointer', marginBottom: 10,
            }}
          >
            Try Again
          </button>
        )}
        <button
          onClick={onSignOut}
          style={{
            width: '100%', background: 'transparent', border: '1px solid rgba(59,42,31,0.2)', color: '#3B2A1F',
            borderRadius: 6, padding: '10px 0', fontSize: 13.5, fontWeight: 500, cursor: 'pointer',
          }}
        >
          Sign Out
        </button>
      </div>
    </div>
  );
}

function Sidebar({ view, setView, lowCount, role, pendingCount, logo, onSignOut }) {
  const structure = [
    { type: 'item', key: 'overview', label: 'Overview', icon: LayoutGrid },
    { type: 'item', key: 'pos', label: 'Point of Sale', icon: ShoppingCart },
    { type: 'group', label: 'Stock Management', icon: Boxes, children: [
      { key: 'inventory', label: 'Inventory', icon: Boxes },
      { key: 'staffInventory', label: 'Staff Inventory', icon: User },
      { key: 'suppliers', label: 'Suppliers', icon: Truck },
      { key: 'orders', label: 'Orders', icon: ClipboardList },
      { key: 'categories', label: 'Categories', icon: Tag },
      { key: 'locations', label: 'Zonal Locations', icon: MapPin },
    ] },
    { type: 'item', key: 'mysales', label: 'My Sales', icon: Receipt },
    { type: 'group', label: 'Reports', icon: ScrollText, children: [
      { key: 'delivery', label: 'Delivery Times', icon: Timer },
      { key: 'sales', label: 'Sales History', icon: Receipt },
      { key: 'history', label: 'Transaction History', icon: ScrollText },
      { key: 'activity', label: 'Activity Log', icon: Clock },
    ] },
    { type: 'group', label: 'User Profiles', icon: User, children: [
      { key: 'approvals', label: 'Team', icon: User, badge: pendingCount },
      { key: 'myprofile', label: 'My Profile', icon: User },
    ] },
  ];

  // Resolve visibility: flat items check their own permission; groups are
  // shown only if at least one child is visible to this role, and only
  // their visible children render.
  const resolved = structure
    .map((entry) => {
      if (entry.type === 'item') {
        return canAccessView(role, entry.key) ? entry : null;
      }
      const children = entry.children.filter((c) => canAccessView(role, c.key));
      return children.length ? { ...entry, children } : null;
    })
    .filter(Boolean);

  const activeGroupLabel = resolved.find((e) => e.type === 'group' && e.children.some((c) => c.key === view))?.label;
  const [openGroup, setOpenGroup] = useState(activeGroupLabel || null);

  const toggleGroup = (label) => setOpenGroup((prev) => (prev === label ? null : label));

  return (
    <aside style={styles.sidebar} className="depot-sidebar">
      <div style={styles.brand} className="depot-brand">
        <div style={styles.logoCard}>
          <img src={logo} alt="Company logo" style={styles.logoImg} />
        </div>
      </div>
      <nav style={{ display: 'flex', flexDirection: 'column', gap: 4, marginTop: 28 }} className="depot-sidebar-nav">
        {resolved.map((entry) => {
          if (entry.type === 'item') {
            const { key, label, icon: Icon } = entry;
            return (
              <button
                key={key}
                className={`depot-btn depot-nav-btn${view === key ? ' depot-nav-active' : ''}`}
                onClick={() => setView(key)}
                style={{
                  ...styles.navBtn,
                  background: view === key ? 'rgba(201,169,106,0.14)' : 'transparent',
                  color: view === key ? '#fff' : 'rgba(245,243,236,0.65)',
                  borderLeft: view === key ? '3px solid var(--amber)' : '3px solid transparent',
                }}
              >
                <Icon size={16} strokeWidth={2} />
                <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{label}</span>
                {key === 'inventory' && lowCount > 0 && (
                  <span style={styles.navBadge}>{lowCount}</span>
                )}
              </button>
            );
          }
          const isOpen = openGroup === entry.label;
          const GroupIcon = entry.icon;
          const groupBadge = entry.children.reduce((sum, c) => sum + (c.badge || 0), 0);
          return (
            <div key={entry.label}>
              <button
                className="depot-btn depot-nav-btn"
                onClick={() => toggleGroup(entry.label)}
                style={{
                  ...styles.navBtn,
                  background: 'transparent', color: 'rgba(245,243,236,0.65)', borderLeft: '3px solid transparent',
                }}
              >
                <GroupIcon size={16} strokeWidth={2} />
                <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{entry.label}</span>
                {groupBadge > 0 && <span style={styles.navBadge}>{groupBadge}</span>}
                <ChevronDown size={13} style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s ease' }} />
              </button>
              {isOpen && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 2, marginTop: 2 }}>
                  {entry.children.map(({ key, label, icon: Icon, badge }) => (
                    <button
                      key={key}
                      className={`depot-btn depot-nav-btn${view === key ? ' depot-nav-active' : ''}`}
                      onClick={() => setView(key)}
                      style={{
                        ...styles.navBtn, paddingLeft: 34, fontSize: 12.5,
                        background: view === key ? 'rgba(201,169,106,0.14)' : 'transparent',
                        color: view === key ? '#fff' : 'rgba(245,243,236,0.55)',
                        borderLeft: view === key ? '3px solid var(--amber)' : '3px solid transparent',
                      }}
                    >
                      <Icon size={14} strokeWidth={2} />
                      <span style={{ flex: 1, textAlign: 'left' }} className="depot-nav-label">{label}</span>
                      {badge > 0 && <span style={styles.navBadge}>{badge}</span>}
                    </button>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </nav>
      <div style={styles.sidebarFoot} className="depot-sidebar-foot">
        <Clock size={12} />
        <span>{new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}</span>
      </div>
      <button
        className="depot-btn depot-signout-btn"
        onClick={onSignOut}
        style={{
          marginTop: 8, background: 'transparent', border: '1px solid rgba(245,243,236,0.2)',
          color: 'rgba(245,243,236,0.7)', fontSize: 11.5, borderRadius: 5, padding: '7px 12px',
        }}
      >
        Sign Out
      </button>
    </aside>
  );
}

function TopBar({ view, role, onAdd }) {
  const titles = {
    overview: ['Overview', 'Warehouse status at a glance'],
    pos: ['Point of Sale', 'Ring up a sale and update stock'],
    inventory: ['Inventory', 'Every SKU on the floor'],
    staffInventory: ['Staff Inventory', 'Stock assigned to each staff member'],
    suppliers: ['Suppliers', 'Vendors you order stock from'],
    orders: ['Orders', 'Purchase orders placed with your suppliers'],
    categories: ['Categories', 'Organize items into your own groups'],
    locations: ['Zonal Locations', 'Manage where stock is stored'],
    delivery: ['Delivery Times', 'Lead times and expected restocks'],
    sales: ['Sales History', 'Every completed transaction'],
    history: ['Transaction History', 'Full receiving & issue ledger'],
    approvals: ['Team', 'Manage your team roster, roles, and approvals'],
    mysales: ['My Sales', 'Transactions you\'ve processed'],
    activity: ['Activity Log', 'Sign-in and sign-out history'],
    myprofile: ['My Profile', 'Your personal details'],
  };
  const [title, sub] = titles[view];
  const showAdd = (view === 'inventory' && can(role, 'editInventory')) || (view === 'suppliers' && can(role, 'manageSuppliers'))
    || (view === 'orders' && can(role, 'manageOrders'));
  return (
    <div style={styles.topbar} className="depot-topbar">
      <div>
        <h1 style={styles.h1} className="depot-h1">{title}</h1>
        <p style={styles.subtext}>{sub}</p>
      </div>
      {showAdd && (
        <button className="depot-btn depot-no-print depot-topbar-btn" style={styles.primaryBtn} onClick={onAdd}>
          <Plus size={16} /> {view === 'suppliers' ? 'New Supplier' : view === 'orders' ? 'New Order' : 'New Item'}
        </button>
      )}
    </div>
  );
}

function StatCard({ icon: Icon, label, value, accent }) {
  return (
    <div style={styles.statCard} className="depot-stat-card">
      <div style={{ ...styles.statIcon, background: accent }}>
        <Icon size={18} color="#fff" strokeWidth={2.2} />
      </div>
      <div>
        <div style={styles.statValue}>{value}</div>
        <div style={styles.statLabel}>{label}</div>
      </div>
    </div>
  );
}

function Overview({ totals, categoryData, profitStats, role, onQuickMove }) {
  const canViewProfit = can(role, 'viewSalesReports');
  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.statGrid} className="depot-stat-grid">
        <StatCard icon={Package} label="SKUs Tracked" value={totals.totalSkus} accent="var(--blueprint)" />
        <StatCard icon={Boxes} label="Units on Hand" value={totals.totalUnits.toLocaleString()} accent="#2E5C87" />
        <StatCard icon={PesoIcon} label="Inventory Value" value={currency(totals.totalValue)} accent="var(--green)" />
        <StatCard icon={AlertTriangle} label="Low Stock Alerts" value={totals.lowStock.length} accent={totals.lowStock.length ? 'var(--red)' : 'var(--blueprint)'} />
      </div>

      <div style={styles.overviewGrid} className="depot-overview-grid">
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <ListOrdered size={15} />
            <span>UNITS BY CATEGORY</span>
          </div>
          <div style={{ height: 220 }}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={categoryData} margin={{ top: 10, right: 10, left: -10, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(59,42,31,0.08)" vertical={false} />
                <XAxis dataKey="category" tick={{ fontFamily: 'Quicksand', fontSize: 11, fill: '#3B2A1F' }} axisLine={{ stroke: 'rgba(59,42,31,0.15)' }} tickLine={false} />
                <YAxis tick={{ fontFamily: 'Quicksand', fontSize: 11, fill: '#3B2A1F' }} axisLine={false} tickLine={false} />
                <Tooltip
                  contentStyle={{ fontFamily: 'Quicksand', fontSize: 12, border: '1px solid #3B2A1F', borderRadius: 4 }}
                  cursor={{ fill: 'rgba(15,42,71,0.06)' }}
                />
                <Bar dataKey="units" radius={[3, 3, 0, 0]}>
                  {categoryData.map((_, idx) => (
                    <Cell key={idx} fill={idx % 2 === 0 ? '#2F4A32' : '#C9A96A'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <AlertTriangle size={15} />
            <span>REORDER WATCHLIST</span>
          </div>
          {totals.lowStock.length === 0 ? (
            <div style={styles.emptyState}>All items are above their reorder point.</div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10 }}>
              {totals.lowStock.map((it) => (
                <div key={it.id} style={styles.watchRow}>
                  <div>
                    <div style={styles.watchSku}>{it.sku}</div>
                    <div style={styles.watchName}>{it.name}</div>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <span style={styles.watchQty}>{it.quantity} / {it.reorderPoint}</span>
                    <button className="depot-btn" style={styles.smallAmberBtn} onClick={() => onQuickMove(it)}>
                      Receive
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Profit is commercially sensitive (it reveals cost basis and
          margins) - only managers who can already view Reports get to see
          it. Staff never see this section, even though they see Overview. */}
      {canViewProfit && (
        <>
          <div style={{ ...styles.panelHeader, marginTop: 24, marginBottom: 10 }}>
            <PesoIcon size={15} />
            <span>PROFIT TRACKER</span>
          </div>

          <div style={styles.statGrid} className="depot-stat-grid">
            <StatCard icon={PesoIcon} label="Total Profit" value={currency(profitStats.totalProfit)} accent={profitStats.totalProfit >= 0 ? 'var(--green)' : 'var(--red)'} />
            <StatCard icon={Receipt} label="Total Revenue" value={currency(profitStats.totalRevenue)} accent="var(--blueprint)" />
            <StatCard icon={Package} label="Cost of Goods Sold" value={currency(profitStats.totalCost)} accent="#2E5C87" />
            <StatCard icon={CheckCircle2} label="Profit Margin" value={`${profitStats.margin.toFixed(1)}%`} accent={profitStats.margin >= 0 ? 'var(--green)' : 'var(--red)'} />
          </div>

          <div style={styles.overviewGrid} className="depot-overview-grid">
            <div style={styles.panel}>
              <div style={styles.panelHeader}>
                <Boxes size={15} />
                <span>PROFIT BY ITEM</span>
              </div>
              {profitStats.profitByItem.length === 0 ? (
                <div style={styles.emptyState}>No completed sales yet.</div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10, maxHeight: 240, overflowY: 'auto' }} className="depot-scroll">
                  {profitStats.profitByItem.slice(0, 10).map((row) => (
                    <div key={row.itemId} style={styles.watchRow}>
                      <div>
                        <div style={styles.watchSku}>{row.sku}</div>
                        <div style={styles.watchName}>{row.name} · {row.qty} sold</div>
                      </div>
                      <span style={{ fontWeight: 700, color: row.profit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(row.profit)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={styles.panel}>
              <div style={styles.panelHeader}>
                <Receipt size={15} />
                <span>PROFIT PER SALE</span>
              </div>
              {profitStats.perSale.length === 0 ? (
                <div style={styles.emptyState}>No completed sales yet.</div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginTop: 10, maxHeight: 240, overflowY: 'auto' }} className="depot-scroll">
                  {profitStats.perSale.map((s) => (
                    <div key={s.id} style={styles.watchRow}>
                      <div>
                        <div style={styles.watchSku}>{s.receiptNo}</div>
                        <div style={styles.watchName}>{formatDate(s.timestamp)} · Revenue {currency(s.revenue)}</div>
                      </div>
                      <span style={{ fontWeight: 700, color: s.profit >= 0 ? 'var(--green)' : 'var(--red)' }}>{currency(s.profit)}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function InventoryView({ filtered, supplierMap, categories, role, search, setSearch, categoryFilter, setCategoryFilter, sortKey, setSortKey, onEdit, onDelete, onMove, onEditMarkup }) {
  const supplierNames = (it) => getSupplierIds(it).map((sid) => supplierMap[sid]?.name).filter(Boolean);

  const exportHeaders = ['SKU', 'Name', 'Category', 'Suppliers', 'Location', 'Quantity', 'Base Cost', 'Selling Price', 'Value'];
  const exportRows = () => filtered.map((it) => [
    it.sku, it.name, it.category, supplierNames(it).join('; '), it.location,
    it.quantity, it.unitCost.toFixed(2), (it.sellingPrice ?? it.unitCost).toFixed(2), (it.quantity * it.unitCost).toFixed(2),
  ]);
  const handleDownload = () => downloadCSV('inventory.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('inventory.pdf', 'Inventory', exportHeaders, exportRows());
  const canEdit = can(role, 'editInventory');
  const canEditMarkup = can(role, 'editMarkup');
  const canDelete = can(role, 'deleteInventory');
  const canMove = can(role, 'stockReceive') || can(role, 'stockIssue');
  const showActionsCol = canEdit || canDelete || canMove || canEditMarkup;

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      {can(role, 'print') && <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />}
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by name or SKU…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <select className="depot-select" value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)} style={styles.select}>
          <option value="All">All Categories</option>
          {categories.map((c) => <option key={c} value={c}>{c}</option>)}
        </select>
        <select className="depot-select" value={sortKey} onChange={(e) => setSortKey(e.target.value)} style={styles.select}>
          <option value="name">Sort: Name</option>
          <option value="qty">Sort: Quantity</option>
          <option value="value">Sort: Value</option>
          <option value="low">Sort: Closest to Reorder</option>
        </select>
      </div>

      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['SKU', 'Item', 'Category', 'Suppliers', 'Location', 'Qty', 'Base Cost', 'Selling Price', 'Value', ...(showActionsCol ? [''] : [])].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={10} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No items match your search.</td></tr>
            )}
            {filtered.map((it) => {
              const low = it.quantity <= it.reorderPoint;
              const names = supplierNames(it);
              return (
                <tr key={it.id} className="depot-row">
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>{it.sku}</td>
                  <td style={styles.td}>{it.name}</td>
                  <td style={styles.td}><span style={styles.pill}>{it.category}</span></td>
                  <td style={{ ...styles.td, fontSize: 12.5, color: names.length ? 'var(--ink)' : 'rgba(59,42,31,0.4)' }}>
                    {names.length ? names.join(', ') : '— none —'}
                  </td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontSize: 12, color: 'rgba(59,42,31,0.6)' }}>
                    <MapPin size={11} style={{ marginRight: 3, verticalAlign: -1 }} />{it.location}
                  </td>
                  <td style={styles.td}>
                    <span style={{ color: low ? 'var(--red)' : 'var(--ink)', fontWeight: low ? 700 : 500 }}>{it.quantity}</span>
                    {low && <AlertTriangle size={12} color="var(--red)" style={{ marginLeft: 5, verticalAlign: -1 }} />}
                  </td>
                  <td style={styles.td}>{currency(it.unitCost)}</td>
                  <td style={styles.td}>{currency(it.sellingPrice ?? it.unitCost)}</td>
                  <td style={styles.td}>{currency(it.quantity * it.unitCost)}</td>
                  {showActionsCol && (
                    <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                      {canMove && <IconBtn onClick={() => onMove(it)} title="Record movement"><ArrowUpCircle size={15} /></IconBtn>}
                      {canEdit && <IconBtn onClick={() => onEdit(it)} title="Edit"><Pencil size={14} /></IconBtn>}
                      {!canEdit && canEditMarkup && <IconBtn onClick={() => onEditMarkup(it)} title="Update markup"><PesoIcon size={14} /></IconBtn>}
                      {canDelete && <IconBtn onClick={() => onDelete(it)} title="Delete" danger><Trash2 size={14} /></IconBtn>}
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function StaffInventoryView({ items, staffList, selectedStaffUid, setSelectedStaffUid, onAssign, onEdit, onDelete, onMove }) {
  const staffItems = useMemo(
    () => items.filter((it) => it.holderId === selectedStaffUid),
    [items, selectedStaffUid]
  );
  const selectedStaff = staffList.find((s) => s.id === selectedStaffUid);

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <select className="depot-select" value={selectedStaffUid} onChange={(e) => setSelectedStaffUid(e.target.value)} style={styles.select}>
          <option value="">— Select a staff member —</option>
          {staffList.map((s) => <option key={s.id} value={s.id}>{s.fullName || s.email}</option>)}
        </select>
        {selectedStaffUid && (
          <button className="depot-btn" style={styles.primaryBtn} onClick={onAssign}>
            <Plus size={16} /> Assign Inventory
          </button>
        )}
      </div>

      {staffList.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No staff accounts yet — create one from Team Access.</div></div>
      ) : !selectedStaffUid ? (
        <div style={styles.panel}><div style={styles.emptyState}>Pick a staff member above to view and manage their inventory.</div></div>
      ) : staffItems.length === 0 ? (
        <div style={styles.panel}>
          <div style={styles.emptyState}>{selectedStaff?.fullName || selectedStaff?.email} has no assigned inventory yet.</div>
        </div>
      ) : (
        <div style={styles.tableWrap} className="depot-scroll">
          <table style={styles.table} className="depot-table">
            <thead>
              <tr>
                {['SKU', 'Item', 'Category', 'Qty', 'Base Cost', 'Markup', 'Selling Price', 'Value', ''].map((h) => (
                  <th key={h} style={styles.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {staffItems.map((it) => {
                const low = it.quantity <= it.reorderPoint;
                const markupLabel = it.markupType === 'fixed' ? `${currency(it.markupValue || 0)} flat` : `${it.markupValue || 0}%`;
                return (
                  <tr key={it.id} className="depot-row">
                    <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif", fontWeight: 500 }}>{it.sku}</td>
                    <td style={styles.td}>{it.name}</td>
                    <td style={styles.td}><span style={styles.pill}>{it.category}</span></td>
                    <td style={styles.td}>
                      <span style={{ color: low ? 'var(--red)' : 'var(--ink)', fontWeight: low ? 700 : 500 }}>{it.quantity}</span>
                      {low && <AlertTriangle size={12} color="var(--red)" style={{ marginLeft: 5, verticalAlign: -1 }} />}
                    </td>
                    <td style={styles.td}>{currency(it.unitCost)}</td>
                    <td style={styles.td}>{markupLabel}</td>
                    <td style={styles.td}>{currency(it.sellingPrice ?? it.unitCost)}</td>
                    <td style={styles.td}>{currency(it.quantity * it.unitCost)}</td>
                    <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                      <IconBtn onClick={() => onMove(it)} title="Record movement"><ArrowUpCircle size={15} /></IconBtn>
                      <IconBtn onClick={() => onEdit(it)} title="Edit"><Pencil size={14} /></IconBtn>
                      <IconBtn onClick={() => onDelete(it)} title="Remove" danger><Trash2 size={14} /></IconBtn>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function SuppliersView({ suppliers, items, onEdit, onDelete }) {
  const countFor = (sid) => items.filter((it) => getSupplierIds(it).includes(sid)).length;

  const exportHeaders = ['Name', 'Contact', 'Phone', 'Email', 'Lead Time (days)', 'Items Supplied', 'Notes'];
  const exportRows = () => suppliers.map((s) => [s.name, s.contact, s.phone, s.email, s.leadTimeDays, countFor(s.id), s.notes]);
  const handleDownload = () => downloadCSV('suppliers.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('suppliers.pdf', 'Suppliers', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      {suppliers.length === 0 ? (
        <div style={styles.panel}><div style={styles.emptyState}>No suppliers yet. Add your first one.</div></div>
      ) : (
        <div style={styles.supplierGrid} className="depot-card-grid">
          {suppliers.map((s) => (
            <div key={s.id} style={styles.supplierCard}>
              <div style={styles.supplierCardHead}>
                <div style={styles.supplierIcon}><Truck size={16} color="#fff" /></div>
                <div style={{ flex: 1 }}>
                  <div style={styles.supplierName}>{s.name}</div>
                  <div style={styles.supplierMeta}>{countFor(s.id)} item{countFor(s.id) === 1 ? '' : 's'} supplied</div>
                </div>
                <div className="depot-no-print" style={{ display: 'flex', gap: 6 }}>
                  <IconBtn onClick={() => onEdit(s)} title="Edit"><Pencil size={13} /></IconBtn>
                  <IconBtn onClick={() => onDelete(s)} title="Delete" danger><Trash2 size={13} /></IconBtn>
                </div>
              </div>
              <div style={styles.supplierBody}>
                <div style={styles.supplierRow}><User size={13} /> {s.contact || '—'}</div>
                <div style={styles.supplierRow}><Phone size={13} /> {s.phone || '—'}</div>
                <div style={styles.supplierRow}><Mail size={13} /> {s.email || '—'}</div>
                <div style={styles.supplierRow}><Timer size={13} /> {s.leadTimeDays} day lead time</div>
                {s.notes && <div style={styles.supplierNotes}>{s.notes}</div>}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function OrdersView({ orders, onReceive, onCancel }) {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');

  const filtered = useMemo(() => {
    return orders.filter((o) => {
      const matchesStatus = statusFilter === 'All' || o.status === statusFilter.toLowerCase();
      const q = search.toLowerCase();
      const matchesSearch = !q || o.itemSku.toLowerCase().includes(q) || o.itemName.toLowerCase().includes(q)
        || o.supplierName.toLowerCase().includes(q);
      return matchesStatus && matchesSearch;
    });
  }, [orders, search, statusFilter]);

  const statusStyle = (status) => {
    if (status === 'pending') return { bg: 'rgba(15,42,71,0.08)', color: 'var(--blueprint)' };
    if (status === 'cancelled') return { bg: 'rgba(193,84,60,0.1)', color: 'var(--red)' };
    return { bg: 'rgba(79,138,99,0.1)', color: 'var(--green)' }; // received
  };

  const exportHeaders = ['Order Date', 'Item', 'Supplier', 'Quantity', 'Unit Cost', 'Total', 'Expected By', 'Status', 'Notes'];
  const exportRows = () => filtered.map((o) => [
    formatDate(o.orderDate), `${o.itemSku} — ${o.itemName}`, o.supplierName, o.quantity,
    o.unitCost.toFixed(2), o.totalCost.toFixed(2), formatDate(o.expectedDate), o.status, o.notes || '',
  ]);
  const handleDownload = () => downloadCSV('orders.csv', exportHeaders, exportRows());
  const handleDownloadPDF = () => downloadPDF('orders.pdf', 'Orders', exportHeaders, exportRows());

  return (
    <div style={{ animation: 'fadeIn 0.3s ease' }}>
      <ExportBar onPrint={printPage} onDownload={handleDownload} onDownloadPDF={handleDownloadPDF} />
      <div style={styles.filterBar} className="depot-no-print depot-filterbar">
        <div style={styles.searchBox}>
          <Search size={15} color="rgba(59,42,31,0.5)" />
          <input
            className="depot-input"
            placeholder="Search by item or supplier…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={styles.searchInput}
          />
        </div>
        <select className="depot-select" value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} style={styles.select}>
          <option value="All">All Statuses</option>
          <option value="Pending">Pending</option>
          <option value="Received">Received</option>
          <option value="Cancelled">Cancelled</option>
        </select>
      </div>

      <div style={styles.tableWrap} className="depot-scroll">
        <table style={styles.table} className="depot-table">
          <thead>
            <tr>
              {['Order Date', 'Item', 'Supplier', 'Qty', 'Unit Cost', 'Total', 'Expected By', 'Status', ''].map((h) => (
                <th key={h} style={styles.th}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={9} style={{ ...styles.td, textAlign: 'center', padding: '32px 0', color: 'rgba(59,42,31,0.5)' }}>No orders match your filters.</td></tr>
            )}
            {filtered.map((o) => {
              const st = statusStyle(o.status);
              return (
                <tr key={o.id} className="depot-row">
                  <td style={styles.td}>{formatDate(o.orderDate)}</td>
                  <td style={{ ...styles.td, fontFamily: "'Quicksand', sans-serif" }}>
                    {o.itemSku} <span style={{ fontFamily: "'Nunito', sans-serif", color: 'rgba(59,42,31,0.55)' }}>— {o.itemName}</span>
                  </td>
                  <td style={styles.td}>{o.supplierName}</td>
                  <td style={styles.td}>{o.quantity}</td>
                  <td style={styles.td}>{currency(o.unitCost)}</td>
                  <td style={styles.td}>{currency(o.totalCost)}</td>
                  <td style={styles.td}>{formatDate(o.expectedDate)}</td>
                  <td style={styles.td}>
                    <span style={{ ...styles.statusPill, background: st.bg, color: st.color }}>
                      {o.status === 'received' && <CheckCircle2 size={12} />}
                      {o.status.charAt(0).toUpperCase() + o.status.slice(1)}
                    </span>
                  </td>
                  <td className="depot-no-print" style={{ ...styles.td, display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                    {o.status === 'pending' && (
                      <>
                        <IconBtn onClick={() => onReceive(o)} title="Mark received"><CheckCircle2 size={14} /></IconBtn>
                        <IconBtn onClick={() => onCancel(o)} title="Cancel order" danger><X size={14} /></IconBtn>
                      </>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

